async function addPaymentAsset(env, householdId = "", data = {}) {
  const name = String(data.name || "").trim().slice(0, 80);
  if (!name) return { ok: false, error: "이름을 입력해주세요." };
  const kind = ["credit_card","check_card","cash","bank_account","asset","easy_pay"].includes(data.kind) ? data.kind : "credit_card";
  const current = await fetchPaymentAssets(env, householdId);
  const next = current.filter((x) => normalizeText(x.name) !== normalizeText(name));
  next.push({
    id: `asset_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`,
    household_id: householdId || "",
    name,
    kind,
    issuer: String(data.issuer || "").trim().slice(0, 80),
    balance: Math.round(Number(data.balance || 0)),
    include_in_asset: data.include_in_asset === false ? false : true,
    memo: String(data.memo || "").trim().slice(0, 120),
    created_at: new Date().toISOString(),
  });
  await savePaymentAssets(env, householdId, next);
  return { ok: true };
}

async function deletePaymentAsset(env, householdId = "", id = "") {
  const current = await fetchPaymentAssets(env, householdId);
  await savePaymentAssets(env, householdId, current.filter((x) => String(x.id) !== String(id)));
  return { ok: true };
}

function inferPaymentAssetFromText(text = "", assets = []) {
  const raw = normalizeText(text);
  if (!raw) return "";
  const sorted = safeArray(assets).filter((a) => a.name).sort((a, b) => b.name.length - a.name.length);
  for (const asset of sorted) {
    const name = normalizeText(asset.name);
    if (name && raw.includes(name)) return asset.name;
    const issuer = normalizeText(asset.issuer || "");
    if (issuer && raw.includes(issuer) && /(카드|체크|통장|계좌|페이|현금)/.test(raw)) return asset.name;
  }
  return "";
}

function inferCustomCategoryFromText(text = "", type = "expense", categories = []) {
  const raw = normalizeText(text);
  if (!raw) return "";
  const list = safeArray(categories).filter((c) => c.name && (c.type || "expense") === type).sort((a, b) => {
    const ak = Math.max(normalizeText(a.name).length, ...normalizeCategoryKeywords(a.keywords || "").map((x) => normalizeText(x).length));
    const bk = Math.max(normalizeText(b.name).length, ...normalizeCategoryKeywords(b.keywords || "").map((x) => normalizeText(x).length));
    return bk - ak;
  });
  for (const c of list) {
    for (const kw of normalizeCategoryKeywords(c.keywords || "")) {
      const key = normalizeText(kw);
      if (key && raw.includes(key)) return c.name;
    }
    const name = normalizeText(c.name);
    if (name && raw.includes(name)) return c.name;
  }
  return "";
}

function applyUserSettingsToParsedTransactions(parsedList = [], categories = [], paymentAssets = []) {
  return safeArray(parsedList).map((p) => {
    const baseText = `${p.raw_text || ""} ${p.memo || ""} ${p.category || ""} ${p.payment_method || ""}`;
    const customCategory = inferCustomCategoryFromText(baseText, p.type, categories);
    const customPayment = inferPaymentAssetFromText(baseText, paymentAssets);
    return {
      ...p,
      category: customCategory || p.category,
      payment_method: customPayment || p.payment_method,
    };
  });
}


async function resolveManualInputClassification(env, householdId = "", type = "expense", fields = {}) {
  const cleanType = type === "income" ? "income" : "expense";
  const rawText = normalizeText([fields.raw_text, fields.memo, fields.category, fields.payment_method].filter(Boolean).join(" "));
  const explicitCategory = String(fields.category || "").trim();
  const explicitPayment = String(fields.payment_method || "").trim();
  const baseCategory = explicitCategory || inferCategory(rawText || fields.memo || "", cleanType) || "";
  const basePayment = explicitPayment || detectPaymentMethod(rawText || fields.memo || "") || "";
  try {
    const [customCategoryRows, paymentAssetRows] = await Promise.all([
      fetchCustomCategories(env, householdId),
      fetchPaymentAssets(env, householdId),
    ]);
    const refined = applyUserSettingsToParsedTransactions([{ type: cleanType, raw_text: rawText, memo: fields.memo || "", category: baseCategory, payment_method: basePayment }], customCategoryRows, paymentAssetRows)[0] || {};
    return {
      category: String(refined.category || baseCategory || "").trim(),
      payment_method: String(refined.payment_method || basePayment || "").trim(),
    };
  } catch (err) {
    return { category: baseCategory, payment_method: basePayment };
  }
}

async function handlePaymentAssetCreate(request, env) {
  const form = await request.formData();
  const householdId = String(form.get("household_id") || "").trim();
  const month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const adminOk = await verifyAdminSession(request, env);
  if (!adminOk) {
    const userId = await verifyUserSession(request, env);
    const role = await getHouseholdMemberRole(env, userId, householdId);
    if (!["owner", "admin"].includes(role)) return redirectResponse(`/payment-methods?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(householdId)}&err=${encodeURIComponent("자산·결제수단 저장 권한이 없습니다.")}`);
  }
  try {
    await addPaymentAsset(env, householdId, {
      name: form.get("name"),
      kind: form.get("kind"),
      issuer: form.get("issuer"),
      balance: parseAmountValue(form.get("balance") || "0"),
      include_in_asset: String(form.get("include_in_asset") || "on") !== "off",
      memo: form.get("memo"),
    });
    return redirectResponse(`/payment-methods?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(householdId)}&msg=payment_asset_saved`);
  } catch (err) {
    return redirectResponse(`/payment-methods?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(householdId)}&err=${encodeURIComponent("결제수단 저장을 완료하지 못했습니다.")}`);
  }
}

async function handlePaymentAssetDelete(request, env) {
  const form = await request.formData();
  const householdId = String(form.get("household_id") || "").trim();
  const month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const id = String(form.get("id") || "").trim();
  const adminOk = await verifyAdminSession(request, env);
  if (!adminOk) {
    const userId = await verifyUserSession(request, env);
    const role = await getHouseholdMemberRole(env, userId, householdId);
    if (!["owner", "admin"].includes(role)) return redirectResponse(`/payment-methods?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(householdId)}&err=${encodeURIComponent("자산·결제수단 삭제 권한이 없습니다.")}`);
  }
  try {
    await deletePaymentAsset(env, householdId, id);
    return redirectResponse(`/payment-methods?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(householdId)}&msg=payment_asset_deleted`);
  } catch (err) {
    return redirectResponse(`/payment-methods?month=${encodeURIComponent(month)}&household_id=${encodeURIComponent(householdId)}&err=${encodeURIComponent("결제수단 삭제를 완료하지 못했습니다.")}`);
  }
}


function reservePlansKey(householdId = "") {
  return `reserve_plans:${String(householdId || "default").trim() || "default"}`;
}

function normalizeReservePlanList(value, householdId = "") {
  let raw = value;
  if (typeof raw === "string") {
    try { raw = raw ? JSON.parse(raw) : []; } catch (err) { raw = []; }
  }
  if (raw && !Array.isArray(raw) && Array.isArray(raw.items)) raw = raw.items;
  const arr = Array.isArray(raw) ? raw : [];
  return arr.map((x, i) => {
    const item = safeObject(x);
    const name = String(item.name || "").trim().slice(0, 80);
    if (!name) return null;
    const recurrence = ["annual","semiannual","quarterly","monthly"].includes(item.recurrence) ? item.recurrence : "annual";
    let dueMonths = Array.isArray(item.due_months) ? item.due_months : String(item.due_months || item.due_month || "").split(/[,\s]+/);
    dueMonths = dueMonths.map((m) => Math.max(1, Math.min(12, Number(m || 0)))).filter(Boolean);
    if (!dueMonths.length) dueMonths = recurrence === "semiannual" ? [6, 12] : recurrence === "quarterly" ? [3, 6, 9, 12] : [12];
    dueMonths = [...new Set(dueMonths)].sort((a, b) => a - b);
    const alertDays = Array.isArray(item.alert_days) ? item.alert_days : String(item.alert_days || "90,60,30").split(/[,\s]+/);
    return {
      id: String(item.id || `reserve_${i}_${name}`).replace(/[^\w가-힣:-]/g, "_").slice(0, 120),
      household_id: item.household_id || householdId || "",
      name,
      amount: Math.max(0, Math.round(Number(item.amount || 0))),
      category: String(item.category || "세금/수수료").trim().slice(0, 80),
      payment_method: String(item.payment_method || "").trim().slice(0, 80),
      recurrence,
      due_months: dueMonths,
      due_day: Math.max(1, Math.min(28, Number(item.due_day || 1))),
      alert_days: [...new Set(alertDays.map((d) => Math.max(1, Math.min(365, Number(d || 0)))).filter(Boolean))].sort((a, b) => b - a),
      memo: String(item.memo || "").trim().slice(0, 160),
      created_at: item.created_at || new Date(0).toISOString(),
    };
  }).filter(Boolean);
}

async function fetchReservePlans(env, householdId = "") {
  try {
    const value = await getSettingValue(env, reservePlansKey(householdId));
    return normalizeReservePlanList(value, householdId);
  } catch (err) {
    return [];
  }
}

async function saveReservePlans(env, householdId = "", plans = []) {
  const cleaned = normalizeReservePlanList(plans, householdId);
  await supabase(env, "/rest/v1/accountbook_settings?on_conflict=key", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify({ key: reservePlansKey(householdId), value: JSON.stringify(cleaned) }),
  });
  return cleaned;
}

async function addReservePlan(env, householdId = "", data = {}) {
  const name = String(data.name || "").trim().slice(0, 80);
  const amount = Math.max(0, Math.round(Number(data.amount || 0)));
  if (!name || !amount) throw new Error("이름과 금액을 입력해주세요.");
  const recurrence = ["annual","semiannual","quarterly","monthly"].includes(data.recurrence) ? data.recurrence : "annual";
  let dueMonths = safeArray(data.due_months).map((m) => Math.max(1, Math.min(12, Number(m || 0)))).filter(Boolean);
  if (!dueMonths.length) dueMonths = recurrence === "semiannual" ? [6, 12] : recurrence === "quarterly" ? [3, 6, 9, 12] : [12];
  const current = await fetchReservePlans(env, householdId);
  const id = `reserve_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
  const next = [
    ...current.filter((p) => normalizeText(p.name) !== normalizeText(name)),
    {
      id,
      household_id: householdId || "",
      name,
      amount,
      category: String(data.category || "세금/수수료").trim().slice(0, 80),
      payment_method: String(data.payment_method || "").trim().slice(0, 80),
      recurrence,
      due_months: dueMonths,
      due_day: Math.max(1, Math.min(28, Number(data.due_day || 1))),
      alert_days: safeArray(data.alert_days).length ? data.alert_days : [90, 60, 30],
      memo: String(data.memo || "").trim().slice(0, 160),
      created_at: new Date().toISOString(),
    },
  ];
  await saveReservePlans(env, householdId, next);
  return { ok: true };
}

async function deleteReservePlan(env, householdId = "", id = "") {
  const current = await fetchReservePlans(env, householdId);
  await saveReservePlans(env, householdId, current.filter((p) => String(p.id) !== String(id)));
  return { ok: true };
}

function recurrenceLabel(v = "") {
  return { annual: "연 1회", semiannual: "반기", quarterly: "분기", monthly: "매월" }[v] || "연 1회";
}

function reserveCycleMonths(plan = {}) {
  if (plan.recurrence === "monthly") return 1;
  if (plan.recurrence === "quarterly") return 3;
  if (plan.recurrence === "semiannual") return 6;
  return 12;
}

function dateOnly(d) {
  return new Date(d.getFullYear(), d.getMonth(), d.getDate());
}

function daysBetween(a, b) {
  return Math.ceil((dateOnly(b).getTime() - dateOnly(a).getTime()) / 86400000);
}

function nextReserveDue(plan = {}, fromDate = nowKstDate()) {
  const base = dateOnly(fromDate);
  const year = base.getFullYear();
  const candidates = [];
  const months = safeArray(plan.due_months).length ? safeArray(plan.due_months) : [12];
  for (const y of [year, year + 1]) {
    for (const m of months) {
      const d = new Date(y, Number(m) - 1, Math.max(1, Math.min(28, Number(plan.due_day || 1))));
      if (d >= base) candidates.push(d);
    }
  }
  candidates.sort((a, b) => a - b);
  return candidates[0] || new Date(year + 1, 11, 1);
}

function reservePlanStatus(plan = {}, fromDate = nowKstDate()) {
  const due = nextReserveDue(plan, fromDate);
  const daysLeft = Math.max(0, daysBetween(fromDate, due));
  const cycle = reserveCycleMonths(plan);
  const monthlyReserve = cycle ? Math.ceil(Number(plan.amount || 0) / cycle) : Number(plan.amount || 0);
  const monthsLeft = Math.max(1, Math.ceil(daysLeft / 30));
  const catchupMonthly = Math.ceil(Number(plan.amount || 0) / monthsLeft);
  const maxAlert = Math.max(...safeArray(plan.alert_days || [90,60,30]).map(Number), 0);
  const alert = daysLeft <= maxAlert;
  return {
    plan,
    due_date: formatDate(due),
    days_left: daysLeft,
    cycle_months: cycle,
    monthly_reserve: monthlyReserve,
    catchup_monthly: catchupMonthly,
    alert,
  };
}

function reserveDashboard(plans = [], fromDate = nowKstDate()) {
  const statuses = safeArray(plans).map((p) => reservePlanStatus(p, fromDate)).sort((a, b) => a.days_left - b.days_left);
  const upcoming = statuses.filter((s) => s.alert);
  const monthlyReserveTotal = statuses.reduce((a, s) => a + Number(s.monthly_reserve || 0), 0);
  return { statuses, upcoming, monthlyReserveTotal };
}

function reserveAlertText(plans = [], limit = 3) {
  const d = reserveDashboard(plans);
  if (!d.upcoming.length) return "";
  const lines = d.upcoming.slice(0, limit).map((s) => {
    const p = s.plan;
    return `- ${p.name}: ${s.days_left}일 후 ${numberWithCommas(p.amount)}원\n  준비 권장: 월 ${numberWithCommas(s.monthly_reserve)}원`;
  });
  return `\n\n🔔 준비할 정기지출\n${lines.join("\n")}`;
}

async function kakaoReserveAlert(env, householdId) {
  try {
    const plans = await fetchReservePlans(env, householdId);
    return reserveAlertText(plans, 3);
  } catch (err) {
    return "";
  }
}

function renderReserveStatusCards(statuses = [], canManage = true) {
  if (!statuses.length) return `<p class="note">아직 등록한 정기지출 준비 항목이 없습니다.</p>`;
  return statuses.map((s) => {
    const p = s.plan;
    return `<div class="reserveCard ${s.alert ? "alert" : ""}"><div><b>${escapeHtml(p.name)}</b><span>${escapeHtml(recurrenceLabel(p.recurrence))} · ${escapeHtml(p.category || "")}</span><span>다음 납부일 ${escapeHtml(s.due_date)} · ${numberWithCommas(s.days_left)}일 남음</span></div><div class="reserveAmt"><strong>${numberWithCommas(p.amount)}원</strong><small>월 준비 ${numberWithCommas(s.monthly_reserve)}원</small><small>지금부터 준비 ${numberWithCommas(s.catchup_monthly)}원/월</small></div>${canManage ? `<form method="post" action="/admin/reserve-plan/delete"><input type="hidden" name="household_id" value="${escapeHtml(p.household_id || "")}"/><input type="hidden" name="id" value="${escapeHtml(p.id)}"/><button type="submit">삭제</button></form>` : ""}</div>`;
  }).join("");
}

