async function handleMyProfilePage(request, env, url) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return redirectResponse("/my");
  const user = await fetchUserById(env, userId);
  return htmlResponse(renderMyProfileHtml({ env, user, msg: url.searchParams.get("msg") || "", err: url.searchParams.get("err") || "" }));
}

async function handleMyProfileUpdate(request, env) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return redirectResponse("/my");
  const form = await request.formData();
  const nickname = String(form.get("nickname") || "").trim().slice(0, 80);
  if (!nickname) return redirectResponse("/my/profile?err=nickname_missing");
  await supabase(env, `/rest/v1/users?id=eq.${encodeURIComponent(userId)}`, {
    method: "PATCH",
    headers: { Prefer: "return=minimal" },
    body: JSON.stringify({ nickname }),
  });
  return redirectResponse("/my/profile?msg=updated");
}

function renderMyProfileHtml({ env, user, msg = "", err = "" }) {
  const title = escapeHtml(appName(env));
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title} · 프로필</title><style>body{margin:0;background:#f6f7f9;font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}.wrap{max-width:640px;margin:0 auto;padding:18px}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;box-shadow:0 10px 26px rgba(15,23,42,.06)}input{width:100%;height:44px;border:1px solid #cbd5e1;border-radius:14px;padding:0 12px;font:inherit}button,.btn{height:42px;border:0;border-radius:14px;background:#111827;color:#fff;text-decoration:none;font-weight:950;padding:0 14px;display:inline-flex;align-items:center}.muted{color:#64748b;font-size:13px}.ok{background:#e8f1e9;color:#365b41;border:1px solid #c9decf;border-radius:12px;padding:10px;margin-bottom:10px}.error{background:#f7e8e4;color:#8f463d;border:1px solid #e7c4bd;border-radius:12px;padding:10px;margin-bottom:10px}</style></head><body><main class="wrap"><h1>내 프로필</h1>${msg ? `<div class="ok">${formatMessage(msg)}</div>` : ""}${err ? `<div class="error">${escapeHtml(err)}</div>` : ""}<section class="card"><form method="post" action="/my/profile"><p class="muted">가계부 참여자 명단과 지출자 표시 이름으로 사용됩니다.</p><label>닉네임</label><input name="nickname" value="${escapeHtml(user?.nickname || "")}" placeholder="닉네임"/><p><button type="submit">저장</button> <a class="btn" href="/my" style="background:#e2e8f0;color:#111">내 가계부</a></p></form></section></main></body></html>`;
}

function renderCategoryAdminHtml({ env, households, selected, householdId, custom = [], displayCategories = [], msg = "", err = "" }) {
  const title = escapeHtml(appName(env));
  const presets = DEFAULT_CATEGORIES.map((c) => `<span class="pill">${escapeHtml(c)}</span>`).join("");
  const categoryCards = displayCategories.length ? displayCategories.map((c) => {
    const keywords = normalizeCategoryKeywords(c.keywords || "");
    const keywordText = keywords.join(", ");
    const keywordChips = keywords.length ? keywords.map((k) => `<span class="kw">${escapeHtml(k)}</span>`).join("") : `<span class="emptyKw">키워드 없음</span>`;
    const isCustom = !String(c.id || "").startsWith("default_") && c.storage !== "default" && c.storage !== "default_keyword";
    const deleteForm = isCustom ? `<form method="post" action="/admin/category/delete"><input type="hidden" name="household_id" value="${escapeHtml(c.household_id || householdId)}"/><input type="hidden" name="id" value="${escapeHtml(c.id)}"/><button class="danger" type="submit">삭제</button></form>` : `<span class="baseBadge">기본</span>`;
    return `<div class="catCard"><div class="catHead"><div><b>${escapeHtml(c.name)}</b><span>${c.type === "income" ? "수입" : "지출"}</span></div>${deleteForm}</div><div class="kwBox">${keywordChips}</div><div class="suggestBox"><strong>추천 키워드</strong>${keywordGuideChips(c.name, c.type, keywords)}</div><form class="kwForm" method="post" action="/admin/category-keywords/save"><input type="hidden" name="household_id" value="${escapeHtml(c.household_id || householdId)}"/><input type="hidden" name="type" value="${escapeHtml(c.type || "expense")}"/><input type="hidden" name="name" value="${escapeHtml(c.name)}"/><input name="keywords" value="${escapeHtml(keywordText)}" placeholder="예: 스타벅스, 커피, 투썸"/><button class="primary" type="submit">키워드 저장</button></form></div>`;
  }).join("") : `<p class="muted">분류를 선택하거나 내 분류를 추가하면 키워드를 관리할 수 있습니다.</p>`;
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title} · 분류 설정</title><style>*,*::before,*::after{box-sizing:border-box}body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1120px;margin:0 auto;padding:16px}.hero{background:linear-gradient(135deg,#111827,#2563eb);color:#fff;border-radius:28px;padding:22px;margin:12px 0;box-shadow:0 18px 42px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:28px}.hero p{line-height:1.55;opacity:.92}.card{background:#fff;border:1px solid #e5e7eb;border-radius:24px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.filters,.formGrid,.kwForm{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px;margin-top:10px}.filters select,.filters button,.formGrid input,.formGrid select,.formGrid button,.kwForm input,.kwForm button{height:44px;border:1px solid #d1d5db;border-radius:14px;padding:0 12px;background:#fff;font:inherit}.filters button,.formGrid button,.kwForm button{background:#111827;color:#fff;font-weight:1000}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:10px}.catCard{background:#f8fafc;border:1px solid #e5e7eb;border-radius:20px;padding:14px}.catHead{display:flex;align-items:center;justify-content:space-between;gap:10px}.catHead b{display:block;font-size:17px}.catHead span,.muted{color:#64748b;font-size:13px;line-height:1.45}.pill,.kw,.emptyKw,.baseBadge,.kwSuggest{display:inline-flex;border-radius:999px;padding:6px 10px;margin:3px;font-size:12px;font-weight:900}.pill{background:#f1f5f9;border:1px solid #e2e8f0}.kw{background:#e0f2fe;color:#075985}.kwSuggest{border:1px solid #bfdbfe;background:#eff6ff;color:#1d4ed8;cursor:pointer}.emptyKw{background:#f1f5f9;color:#64748b}.baseBadge{background:#ecfdf5;color:#065f46}.danger{height:34px;border:0;border-radius:11px;background:#fee2e2;color:#991b1b;font-weight:900;padding:0 10px}.ok{background:#e8f1e9;color:#365b41;border:1px solid #c9decf;border-radius:12px;padding:10px}.error{background:#f7e8e4;color:#8f463d;border:1px solid #e7c4bd;border-radius:12px;padding:10px}.tip{background:#ecfdf5;border:1px solid #a7f3d0;color:#065f46;border-radius:16px;padding:12px;line-height:1.55}@media(max-width:760px){.wrap{padding:12px}.hero h1{font-size:24px}.filters,.formGrid,.kwForm{grid-template-columns:1fr}}</style></head><body>${renderUnifiedNav("categories", { householdId })}<main class="wrap"><section class="hero"><h1>분류·키워드 설정</h1><p>같은 단어라도 집마다 분류 기준이 다를 수 있습니다. 예를 들어 “커피”를 식비로 볼 수도 있고, 용돈으로 볼 수도 있습니다. 우리집 기준에 맞게 키워드를 연결하세요.</p><form class="filters" method="get" action="/categories"><select name="household_id"><option value="">가계부 선택</option>${households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === householdId ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("")}</select><button type="submit">조회</button></form></section>${msg ? `<div class="ok">${formatMessage(msg)}</div>` : ""}${err ? `<div class="error">${escapeHtml(err)}</div>` : ""}<section class="card"><h2>내 분류 추가</h2><div class="guideLine">키워드는 순서와 상관없이 동작합니다. 대신 “가족이 실제로 입력할 말”을 넣어야 자동분류가 잘 됩니다. 예: 커피, 스벅, 스타벅스, 점심, 주유, 자동차보험 <a href="/keyword-guide" style="font-weight:1000;color:#1d4ed8">키워드 안내 보기</a></div><form class="formGrid" method="post" action="/admin/category/create"><input type="hidden" name="household_id" value="${escapeHtml(householdId || selected?.id || "")}"/><input name="name" placeholder="예: 용돈, 아이간식, 렌즈소모품"/><select name="type"><option value="expense">지출</option><option value="income">수입</option></select><input name="keywords" placeholder="키워드 예: 커피, 스벅, 편의점"/><button type="submit">추가</button></form><p class="tip">키워드는 쉼표로 여러 개 입력할 수 있습니다. 챗봇 입력과 카드/문자 내역 분류에 우선 반영됩니다.</p></section><section class="card"><h2>기본 분류</h2><p class="muted">기본 분류도 키워드를 연결할 수 있습니다.</p><div>${presets}</div></section><section class="card"><h2>키워드 관리</h2><div class="grid">${categoryCards}</div></section><script>function addKeywordToInput(btn){var form=btn.closest(".catCard")?.querySelector(".kwForm");if(!form)return;var input=form.querySelector('input[name="keywords"]');if(!input)return;var kw=btn.getAttribute("data-kw")||btn.textContent.trim();var parts=input.value.split(/[,\n|/]+/).map(function(x){return x.trim()}).filter(Boolean);if(!parts.some(function(x){return x.toLowerCase()===kw.toLowerCase()})){parts.push(kw)}input.value=parts.join(", ");input.focus()}</script></main></body></html>`;
}

async function handleAdminBulkUpdate(request, env) {
  let form = null;
  let month = currentMonthKst();
  let householdId = "";
  try {
    if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
    form = await request.formData();
    const ids = [...new Set(form.getAll("ids").map((x) => String(x || "").trim()).filter(Boolean))];
    month = validMonth(String(form.get("month") || "")) || currentMonthKst();
    householdId = String(form.get("household_id") || "").trim();

    if (!ids.length) {
      return redirectResponse(returnLocation(form, transactionReturnFallback(month, householdId, { err: "선택된 거래가 없습니다." }), { err: "선택된 거래가 없습니다." }));
    }

    if (String(form.get("bulk_delete") || "") === "1") {
      const result = await bulkDeleteTransactions(env, ids);
      if (result.deleted > 0 && result.failed === 0) {
        return redirectResponse(returnLocation(form, transactionReturnFallback(month, householdId, { msg: "bulk_deleted" }), { msg: `${result.deleted}건 삭제 완료` }));
      }
      if (result.deleted > 0) {
        return redirectResponse(returnLocation(form, transactionReturnFallback(month, householdId, { msg: "bulk_deleted" }), { msg: `${result.deleted}건 삭제 완료, ${result.failed}건 실패` }));
      }
      return redirectResponse(returnLocation(form, transactionReturnFallback(month, householdId, { err: "선택 삭제 실패" }), { err: result.error || "선택 삭제 실패" }));
    }

    const patch = {};
    const bulkType = String(form.get("bulk_quick_type") || form.get("bulk_type") || "").trim();
    const category = String(form.get("bulk_category") || "").trim();
    const payment = String(form.get("bulk_payment_method") || "").trim();
    const date = String(form.get("bulk_transaction_date") || "").trim();
    const userId = String(form.get("bulk_user_id") || "").trim();
    if (bulkType === "income" || bulkType === "expense") patch.type = bulkType;
    if (category) patch.category = category;
    if (payment || String(form.get("clear_payment_method") || "") === "1") patch.payment_method = payment;
    if (date) {
      if (!isValidTransactionDateString(date)) {
        return redirectResponse(returnLocation(form, transactionReturnFallback(month, householdId, { err: "날짜 형식이 올바르지 않습니다." }), { err: "날짜 형식이 올바르지 않습니다." }));
      }
      patch.transaction_date = date;
    }
    if (userId) patch.user_id = userId;

    if (!Object.keys(patch).length) {
      return redirectResponse(returnLocation(form, transactionReturnFallback(month, householdId, { err: "변경할 값이 없습니다." }), { err: "변경할 값이 없습니다." }));
    }

    for (const id of ids) await updateTransaction(env, id, patch);
    return redirectResponse(returnLocation(form, transactionReturnFallback(month, householdId, { msg: "bulk_updated" }), { msg: `${ids.length}건 일괄 수정 완료` }));
  } catch (err) {
    const fallback = transactionReturnFallback(month, householdId, { err: safeError(err) });
    return redirectResponse(form ? returnLocation(form, fallback, { err: safeError(err) }) : fallback);
  }
}

async function bulkDeleteTransactions(env, ids) {
  const cleanIds = [...new Set((ids || []).map((id) => String(id || "").trim()).filter((id) => /^[0-9a-fA-F-]{20,80}$/.test(id)))];
  if (!cleanIds.length) return { deleted: 0, failed: ids.length, error: "삭제 가능한 거래 ID가 없습니다." };

  let deleted = 0;
  let failed = 0;
  let lastError = "";

  for (let i = 0; i < cleanIds.length; i += 80) {
    const chunk = cleanIds.slice(i, i + 80);
    const params = new URLSearchParams();
    params.set("id", `in.(${chunk.join(",")})`);
    try {
      await supabase(env, `/rest/v1/transactions?${params.toString()}`, {
        method: "DELETE",
        headers: { Prefer: "return=minimal" },
      });
      deleted += chunk.length;
    } catch (err) {
      lastError = safeError(err);
      for (const id of chunk) {
        try {
          await supabase(env, `/rest/v1/transactions?id=eq.${encodeURIComponent(id)}`, {
            method: "DELETE",
            headers: { Prefer: "return=minimal" },
          });
          deleted += 1;
        } catch (innerErr) {
          failed += 1;
          lastError = safeError(innerErr);
        }
      }
    }
  }
  return { deleted, failed, error: lastError };
}

function returnLocation(form, fallback, extra = {}) {
  const raw = String(form.get("return_to") || "");
  let path = raw && raw.startsWith("/") && !raw.startsWith("//") ? raw : fallback;
  if (Object.keys(extra).length) {
    const u = new URL(path, "https://dummy.local");
    for (const [k, v] of Object.entries(extra)) if (v !== undefined && v !== null && String(v) !== "") u.searchParams.set(k, String(v));
    path = u.pathname + u.search;
  }
  return path;
}

async function handleImportTemplateCsv(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const header = ["날짜","구분","금액","분류","내용","결제수단"];
  const rows = [
    ["2026-06-18","지출","12000","식비","점심","카드"],
    ["2026-06-18","지출","4500","카페/간식","커피","카카오페이"],
    ["2026-06-25","수입","3000000","급여","월급","계좌이체"],
  ];
  const csv = [header, ...rows].map(r => r.map(v => `"${String(v).replace(/"/g,'""')}"`).join(",")).join("\n");
  return new Response("\ufeff" + csv, {
    headers: {
      "content-type": "text/csv; charset=utf-8",
      "content-disposition": `attachment; filename="accountbook_import_template.csv"`,
      "cache-control": "no-store",
    },
  });
}

async function handleImportTemplateXls(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const html = `<!doctype html><html><head><meta charset="utf-8"></head><body><table border="1"><thead><tr><th>날짜</th><th>구분</th><th>금액</th><th>분류</th><th>내용</th><th>결제수단</th></tr></thead><tbody><tr><td>2026-06-18</td><td>지출</td><td>12000</td><td>식비</td><td>점심</td><td>카드</td></tr><tr><td>2026-06-18</td><td>지출</td><td>4500</td><td>카페/간식</td><td>커피</td><td>카카오페이</td></tr><tr><td>2026-06-25</td><td>수입</td><td>3000000</td><td>급여</td><td>월급</td><td>계좌이체</td></tr></tbody></table></body></html>`;
  return new Response(html, {
    headers: {
      "content-type": "application/vnd.ms-excel; charset=utf-8",
      "content-disposition": `attachment; filename="accountbook_import_template.xls"`,
      "cache-control": "no-store",
    },
  });
}

async function handleAdminImportJson(request, env) {
  try {
    if (!(await verifyAdminSession(request, env))) return jsonResponse({ ok: false, error: "unauthorized", message: "로그인 세션이 만료되었습니다. 새로고침 후 다시 로그인하세요." }, 401);
    const body = await readJson(request);
    const householdId = String(body.household_id || "").trim();
    if (!householdId) return jsonResponse({ ok: false, error: "household_id_required", message: "가계부를 먼저 선택해주세요." }, 400);
    const rawText = String(body.raw_text || "");
    const defaultUserId = String(body.user_id || "").trim();
    const parsed = parseImportedRecords(rawText, householdId, defaultUserId);
    const rows = cleanImportedRowsForInsert(parsed.rows.slice(0, 1000));
    if (!rows.length) return jsonResponse({ ok: false, error: "no_valid_rows", message: "저장 가능한 행을 찾지 못했습니다.", skipped: parsed.skipped }, 400);
    await supabase(env, "/rest/v1/transactions", {
      method: "POST",
      headers: { Prefer: "return=minimal" },
      body: JSON.stringify(rows),
    });
    return jsonResponse({ ok: true, inserted: rows.length, skipped: parsed.skipped, date_samples: rows.slice(0, 5).map(r => r.transaction_date), warnings: parsed.warnings.slice(0, 20) });
  } catch (err) {
    return jsonResponse({ ok: false, error: "import_failed", message: `업로드 저장 실패: ${safeError(err)}` }, 500);
  }
}

function cleanImportedRowsForInsert(rows = []) {
  const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  return (rows || []).map((row) => {
    const out = { ...row };
    if (!uuidRe.test(String(out.user_id || ""))) delete out.user_id;
    if (!out.payment_method) out.payment_method = "";
    if (!out.memo) out.memo = "";
    if (!out.category) out.category = out.type === "income" ? "기타수입" : "기타지출";
    out.amount = Math.max(0, Math.round(Number(out.amount || 0)));
    return out;
  }).filter((row) => row.household_id && row.type && row.amount > 0 && /^20\d{2}-\d{2}-\d{2}$/.test(String(row.transaction_date || "")));
}

function parseImportedRecords(rawText, householdId, defaultUserId = "") {
  const text = String(rawText || "").replace(/\ufeff/g, "").trim();
  const result = { rows: [], skipped: 0, warnings: [] };
  if (!text) return result;
  const table = parseDelimitedText(text);
  if (table.length >= 2 && looksLikeImportHeader(table[0])) {
    const headers = table[0].map(normalizeImportHeader);
    for (let i = 1; i < table.length; i++) {
      const obj = {};
      headers.forEach((h, idx) => { obj[h || `col${idx}`] = table[i][idx] || ""; });
      const row = normalizeImportedObject(obj, householdId, table[i].join(" "), table[i], defaultUserId);
      if (row) result.rows.push(row);
      else { result.skipped++; result.warnings.push(`${i+1}행 제외: 날짜/금액을 확인해주세요.`); }
    }
    return result;
  }
  const lines = text.split(/\r?\n/).map(x => x.trim()).filter(Boolean);
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const cells = splitDelimitedLine(line);
    const looksTableRow = cells.length >= 3;
    if (looksTableRow) {
      const row = normalizeImportedArray(cells, householdId, line, defaultUserId);
      if (row) { result.rows.push(row); continue; }
    }
    const parsed = parseTransaction(line, {});
    if (parsed.ok) {
      result.rows.push({
        household_id: householdId,
        type: parsed.type,
        amount: parsed.amount,
        category: parsed.category,
        memo: parsed.memo || "",
        payment_method: parsed.payment_method || "",
        transaction_date: parsed.transaction_date,
        source: "import_smart",
        raw_text: line,
        ...(defaultUserId ? { user_id: defaultUserId } : {}),
      });
    } else {
      result.skipped++;
      result.warnings.push(`${i+1}행 제외: ${line.slice(0,40)}`);
    }
  }
  return result;
}

function parseDelimitedText(text) {
  return String(text || "").split(/\r?\n/).map(splitDelimitedLine).filter(r => r.some(c => String(c).trim() !== ""));
}

function splitDelimitedLine(line) {
  const delim = line.indexOf("\t") >= 0 ? "\t" : (line.indexOf(";") >= 0 && line.indexOf(",") < 0 ? ";" : ",");
  const out = [];
  let cur = "";
  let quote = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (quote && line[i + 1] === '"') { cur += '"'; i++; }
      else quote = !quote;
    } else if (ch === delim && !quote) {
      out.push(cur.trim());
      cur = "";
    } else {
      cur += ch;
    }
  }
  out.push(cur.trim());
  return out;
}

function looksLikeImportHeader(row) {
  const joined = row.map(normalizeImportHeader).join("|");
  return /(date|datetime|amount|memo|category|payment|type|날짜|일자|일시|거래일|사용일|이용일|승인일|결제일|금액|내용|분류|수단|구분|입금|출금|적요|가맹점|사용처)/.test(joined);
}

function normalizeImportHeader(value) {
  return normalizeText(value).toLowerCase().replace(/\s+/g, "").replace(/[()_\-./]/g, "");
}

function getImportValue(obj, patterns) {
  const entries = Object.entries(obj).map(([key, value]) => [normalizeImportHeader(key), value]);
  const normalizedPatterns = patterns.map(normalizeImportHeader);
  for (const p of normalizedPatterns) {
    if (!p) continue;
    for (const [nk, value] of entries) {
      if (!nk) continue;
      if (nk === p || nk.indexOf(p) >= 0 || p.indexOf(nk) >= 0) return value;
    }
  }
  return "";
}

function findImportDateInValues(values) {
  for (const value of values || []) {
    const d = parseDateStrict(value);
    if (d) return d;
  }
  return "";
}

function normalizeImportedArray(cells, householdId, raw, defaultUserId = "") {
  const [a,b,c,d,e,f] = cells;
  const transactionDate = findImportDateInValues(cells) || parseExplicitDateFromText(raw);
  if (!transactionDate) return null;
  const amount = parseAmountValue(c || b || raw);
  if (!amount) return null;
  const line = raw || cells.join(" ");
  const type = normalizeType(b) || detectType(line);
  const category = d || inferCategory(line, type);
  return {
    household_id: householdId,
    ...(defaultUserId ? { user_id: defaultUserId } : {}),
    type,
    amount: Math.abs(Math.round(amount)),
    category,
    memo: e || cleanMemo(line, String(amount), type, normalizePaymentMethod(f), category),
    payment_method: normalizePaymentMethod(f || line),
    transaction_date: transactionDate,
    source: "import_smart",
    raw_text: line,
  };
}

function normalizeImportedObject(obj, householdId, raw, cells = [], defaultUserId = "") {
  const rawText = raw || Object.values(obj).join(" ");
  const dateVal = getImportValue(obj, ["날짜","일자","일시","거래일","거래일자","거래일시","사용일","사용일자","이용일","이용일자","승인일","승인일자","승인일시","결제일","결제일자","매입일","작성일","등록일","date","datetime","transactiondate"]);
  const transactionDate = parseDateStrict(dateVal) || findImportDateInValues(cells) || parseExplicitDateFromText(rawText);
  if (!transactionDate) return null;

  const typeVal = getImportValue(obj, ["수입지출","거래구분","유형","type","구분"]);
  const normalizedType = normalizeType(typeVal);
  let type = normalizedType;

  const incomeVal = getImportValue(obj, ["입금","입금액","수입","수입금액","income","deposit"]);
  const expenseVal = getImportValue(obj, ["실지출","실제지출","최종지출","최종금액","출금","출금액","지출","지출금액","expense","사용금액","승인금액","결제금액","withdrawal"]);
  let amountVal = getImportValue(obj, ["실지출","실제지출","최종지출","최종금액","청구금액","금액","거래금액","승인금액","사용금액","결제금액","amount"]);
  if (!amountVal && incomeVal) { amountVal = incomeVal; type = "income"; }
  if (!amountVal && expenseVal) { amountVal = expenseVal; type = "expense"; }

  const amountRaw = String(amountVal || "").trim();
  let amount = parseAmountValue(amountRaw || rawText);
  if (!amount) return null;

  if (!type) {
    if (/^-/.test(amountRaw) || expenseVal) type = "expense";
    else if (incomeVal) type = "income";
    else type = detectType(rawText);
  }

  let paymentVal = getImportValue(obj, ["결제수단","결제방법","결제","수단","카드","계좌","payment","card"]);
  // Some household templates use "구분" for card/cash type like 현대신용, 체크, 현금.
  if (!paymentVal && typeVal && !normalizedType) paymentVal = typeVal;

  const subCategoryVal = getImportValue(obj, ["소분류","세부분류","상세분류"]);
  const mainCategoryVal = getImportValue(obj, ["대분류","분류","카테고리","category"]);
  const categoryVal = subCategoryVal || mainCategoryVal;
  const memoVal = getImportValue(obj, ["지출내용","수입내용","내용","메모","적요","사용처","가맹점","상호","memo","description","merchant"]);

  const payment = normalizePaymentMethod(paymentVal || rawText);
  const category = categoryVal || inferCategory(`${rawText} ${memoVal}`, type);
  return {
    household_id: householdId,
    ...(defaultUserId ? { user_id: defaultUserId } : {}),
    type,
    amount: Math.abs(Math.round(amount)),
    category,
    memo: memoVal || cleanMemo(rawText, amountRaw, type, payment, category),
    payment_method: payment,
    transaction_date: transactionDate,
    source: "import_smart",
    raw_text: rawText,
  };
}

async function handleAdminCsv(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  const householdId = url.searchParams.get("household_id") || "";
  const type = url.searchParams.get("type") || "all";
  const date = url.searchParams.get("date") || "";
  const q = url.searchParams.get("q") || "";
  const quality = url.searchParams.get("quality") || "all";
  const category = url.searchParams.get("category") || "";
  const paymentMethod = url.searchParams.get("payment_method") || "";
  const rows = await fetchAdminRows(env, { month, householdId, type, date, q, quality, category, payment_method: paymentMethod });
  const header = ["date", "type", "amount", "category", "memo", "payment_method", "source", "raw_text"];
  const lines = [header.join(",")];
  for (const t of rows) {
    const row = [t.transaction_date, t.type, t.amount, t.category, t.memo, t.payment_method, t.source, t.raw_text].map((v) => `"${String(v || "").replace(/"/g, '""')}"`);
    lines.push(row.join(","));
  }
  return new Response("\ufeff" + lines.join("\n"), {
    headers: {
      "content-type": "text/csv; charset=utf-8",
      "content-disposition": `attachment; filename="accountbook_${month}.csv"`,
      "cache-control": "no-store",
    },
  });
}

async function fetchAdminHouseholds(env) {
  return (await supabase(env, "/rest/v1/households?select=id,name,invite_code,created_at&order=created_at.asc", { method: "GET" })) || [];
}

async function getScopedHouseholdsForPage(request, env) {
  const userId = await verifyUserSession(request, env);
  if (userId) return { userId, adminOk: await verifyAdminSession(request, env), households: await fetchUserHouseholds(env, userId), scope: "user" };
  const adminOk = await verifyAdminSession(request, env);
  if (adminOk) return { userId: "", adminOk, households: await fetchAdminHouseholds(env), scope: "admin" };
  return { userId: "", adminOk: false, households: [], scope: "none" };
}

function selectScopedHousehold(households = [], householdId = "") {
  return safeArray(households).find((h) => String(h.id) === String(householdId || "")) || safeArray(households)[0] || null;
}



function memberAliasSettingsKey(householdId = "") {
  return `member_aliases:${String(householdId || "default").trim() || "default"}`;
}

async function fetchMemberAliasMap(env, householdId = "") {
  try {
    const value = await getSettingValue(env, memberAliasSettingsKey(householdId));
    if (!value) return {};
    const parsed = typeof value === "string" ? JSON.parse(value || "{}") : value;
    const out = {};
    for (const [k, v] of Object.entries(safeObject(parsed))) {
      const uid = String(k || "").trim();
      const name = String(v || "").trim().slice(0, 80);
      if (uid && name) out[uid] = name;
    }
    return out;
  } catch (err) {
    return {};
  }
}

async function saveMemberAlias(env, householdId = "", userId = "", alias = "") {
  const hid = String(householdId || "").trim();
  const uid = String(userId || "").trim();
  const name = String(alias || "").trim().slice(0, 80);
  if (!hid || !uid || !name) return {};
  const map = await fetchMemberAliasMap(env, hid);
  map[uid] = name;
  await supabase(env, "/rest/v1/accountbook_settings?on_conflict=key", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify({ key: memberAliasSettingsKey(hid), value: JSON.stringify(map) }),
  });
  return map;
}

function roleRank(role = "") {
  const r = String(role || "member").toLowerCase();
  if (r === "owner") return 60;
  if (r === "admin") return 50;
  if (r === "member") return 40;
  if (r === "viewer") return 30;
  if (r === "pending") return 20;
  if (r === "blocked") return 10;
  return 35;
}

function bestMemberRow(rows = []) {
  const arr = safeArray(rows);
  if (!arr.length) return null;
  return arr.slice().sort((a, b) => {
    const rankDiff = roleRank(b.role) - roleRank(a.role);
    if (rankDiff) return rankDiff;
    return String(b.created_at || "").localeCompare(String(a.created_at || ""));
  })[0] || null;
}

function bestRoleFromRows(rows = []) {
  return String(bestMemberRow(rows)?.role || "");
}

function dedupeMemberRowsByKey(rows = [], keyName = "user_id") {
  const map = new Map();
  for (const row of safeArray(rows)) {
    const key = String(row?.[keyName] || "").trim();
    if (!key) continue;
    const prev = map.get(key);
    if (!prev || roleRank(row.role) > roleRank(prev.role) || (roleRank(row.role) === roleRank(prev.role) && String(row.created_at || "") > String(prev.created_at || ""))) {
      map.set(key, row);
    }
  }
  return [...map.values()].sort((a, b) => String(a.created_at || "").localeCompare(String(b.created_at || "")));
}

async function fetchHouseholdMembers(env, householdId) {
  if (!householdId) return [];
  const rawMembers = await supabase(env, `/rest/v1/household_members?household_id=eq.${encodeURIComponent(householdId)}&select=user_id,role,created_at&order=created_at.asc`, { method: "GET" }) || [];
  const members = dedupeMemberRowsByKey(rawMembers, "user_id");
  const aliases = await fetchMemberAliasMap(env, householdId);
  const out = [];
  for (const m of members) {
    const userRows = m.user_id ? await supabase(env, `/rest/v1/users?id=eq.${encodeURIComponent(m.user_id)}&select=id,nickname,kakao_user_key,created_at&limit=1`, { method: "GET" }) : [];
    const user = userRows?.[0] || {};
    const alias = aliases[m.user_id] || "";
    out.push({
      user_id: m.user_id || "",
      role: m.role || "member",
      nickname: alias || user.nickname || (m.role === "owner" ? "관리자" : "구성원"),
      base_nickname: user.nickname || "",
      display_alias: alias,
      kakao_user_key: user.kakao_user_key || "",
      created_at: m.created_at || user.created_at || "",
    });
  }
  return out;
}


async function fetchAllHouseholdMembersMap(env, households = []) {
  const out = {};
  for (const h of households || []) {
    out[h.id] = await fetchHouseholdMembers(env, h.id);
  }
  return out;
}

async function countHouseholdTransactions(env, householdId) {
  if (!householdId) return 0;
  const rows = await supabase(env, `/rest/v1/transactions?household_id=eq.${encodeURIComponent(householdId)}&select=id&limit=5000`, { method: "GET" }) || [];
  return rows.length;
}


function memberNameMap(members = []) {
  const map = {};
  for (const m of members) if (m.user_id) map[m.user_id] = m.nickname || "구성원";
  return map;
}

function attachSpenderNames(rows = [], members = []) {
  const map = memberNameMap(members);
  return (rows || []).map((t) => ({
    ...t,
    spender_name: t.user_id ? (map[t.user_id] || "이전 구성원") : "미지정",
  }));
}

function renderSpenderOptions(members = [], selected = "", blankLabel = "지출자 미지정") {
  const opts = [`<option value="" ${!selected ? "selected" : ""}>${escapeHtml(blankLabel)}</option>`];
  for (const m of members) {
    if (!m.user_id) continue;
    opts.push(`<option value="${escapeHtml(m.user_id)}" ${selected === m.user_id ? "selected" : ""}>${escapeHtml(m.nickname || "구성원")} (${escapeHtml(m.role || "member")})</option>`);
  }
  return opts.join("");
}

function renderSpenderDatalist(members = []) {
  return `<datalist id="spenderNameList">${members.map((m) => `<option value="${escapeHtml(m.nickname || "")}"></option>`).join("")}</datalist>`;
}

async function fetchAdminRows(env, { month, householdId, type = "all", date = "", q = "", quality = "all", category = "", payment_method = "" }) {
  const start = `${month}-01`;
  const end = nextMonthStart(month);
  const params = new URLSearchParams();
  params.set("select", "id,household_id,user_id,type,amount,category,memo,payment_method,transaction_date,source,raw_text,created_at");
  params.set("transaction_date", `gte.${start}`);
  params.append("transaction_date", `lt.${end}`);
  if (householdId) params.set("household_id", `eq.${householdId}`);
  if (type === "income" || type === "expense") params.set("type", `eq.${type}`);
  if (date) params.set("transaction_date", `eq.${date}`);
  params.set("order", "transaction_date.desc,created_at.desc");
  params.set("limit", "2000");
  let rows = (await supabase(env, `/rest/v1/transactions?${params.toString()}`, { method: "GET" })) || [];
  const needle = String(q || "").trim().toLowerCase();
  if (needle) rows = rows.filter((t) => String(`${t.memo || ""} ${t.category || ""} ${t.payment_method || ""} ${t.raw_text || ""}`).toLowerCase().includes(needle));
  if (category) {
    rows = rows.filter((t) => category === "__missing" ? isMissingCategory(t.category) : String(t.category || "") === category);
  }
  if (payment_method) {
    rows = rows.filter((t) => payment_method === "__missing" ? isMissingPayment(t.payment_method) : String(t.payment_method || "") === payment_method);
  }
  if (quality === "missing_category") rows = rows.filter((t) => isMissingCategory(t.category));
  if (quality === "missing_payment") rows = rows.filter((t) => t.type === "expense" && isMissingPayment(t.payment_method));
  if (quality === "missing_any") rows = rows.filter((t) => isMissingCategory(t.category) || (t.type === "expense" && isMissingPayment(t.payment_method)));
  if (quality === "kakao_only") rows = rows.filter((t) => String(t.source || "").includes("kakao"));
  if (quality === "web_only") rows = rows.filter((t) => String(t.source || "").includes("web"));
  return rows;
}

async function fetchAdminRowsRange(env, { householdId = "", start = "", end = "", type = "all", limit = 6000 }) {
  const params = new URLSearchParams();
  params.set("select", "id,household_id,user_id,type,amount,category,memo,payment_method,transaction_date,source,raw_text,created_at");
  if (start) params.set("transaction_date", `gte.${start}`);
  if (end) params.append("transaction_date", `lt.${end}`);
  if (householdId) params.set("household_id", `eq.${householdId}`);
  if (type === "income" || type === "expense") params.set("type", `eq.${type}`);
  params.set("order", "transaction_date.desc,created_at.desc");
  params.set("limit", String(Math.max(100, Math.min(Number(limit || 6000), 10000))));
  return (await supabase(env, `/rest/v1/transactions?${params.toString()}`, { method: "GET" })) || [];
}


