async function checkTableAvailable(env, table) {
  try {
    await supabase(env, `/rest/v1/${table}?select=*&limit=1`, { method: "GET" });
    return { ok: true, detail: "연결됨" };
  } catch (err) {
    return { ok: false, detail: safeError(err).slice(0, 160) };
  }
}

async function tableCheckPair(env, table) {
  const r = await checkTableAvailable(env, table);
  return [r.ok, r.detail];
}


async function getSettingValue(env, key) {
  const rows = await optionalSupabase(env, `/rest/v1/accountbook_settings?key=eq.${encodeURIComponent(key)}&select=value&limit=1`, { method: "GET" }, []);
  return rows?.[0]?.value || "";
}

async function handleSettingsPasswordUpdate(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const form = await request.formData();
  const current = String(form.get("current_password") || "").trim();
  const next = String(form.get("new_password") || "").trim();
  const confirm = String(form.get("confirm_password") || "").trim();
  if (!(await checkAdminPassword(env, current))) return redirectResponse("/settings?err=current_password_wrong");
  if (next.length < 6) return redirectResponse("/settings?err=password_too_short");
  if (next !== confirm) return redirectResponse("/settings?err=password_mismatch");
  const salt = randomHex(16);
  const hash = await sha256Hex(`${salt}:${next}`);
  try {
    await supabase(env, "/rest/v1/accountbook_settings?on_conflict=key", {
      method: "POST",
      headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify({ key: "admin_password_hash", value: `${salt}:${hash}` }),
    });
    return redirectResponse("/settings?msg=password_updated", {
      "set-cookie": "ab_admin=; Path=/; Max-Age=0; HttpOnly; Secure; SameSite=Lax",
    });
  } catch (err) {
    return redirectResponse("/settings?err=settings_table_required");
  }
}

async function handleSettingsPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const settingValue = await getSettingValue(env, "admin_password_hash");
  const msg = url.searchParams.get("msg") || "";
  const err = url.searchParams.get("err") || "";
  return htmlResponse(renderSettingsHtml({ env, hasDbPassword: !!settingValue, msg, err }));
}

function renderSettingsHtml({ env, hasDbPassword, msg = "", err = "" }) {
  const title = escapeHtml(appName(env));
  const errMap = {
    current_password_wrong: "현재 비밀번호가 맞지 않습니다.",
    password_too_short: "새 비밀번호는 6자 이상으로 입력하세요.",
    password_mismatch: "새 비밀번호 확인이 일치하지 않습니다.",
    settings_table_required: "설정 저장 테이블이 없습니다. 설정 저장 구조을 관리자 설정에서 실행하세요.",
  };
  const msgMap = {
    password_updated: "관리자 비밀번호를 변경했습니다. 다시 로그인하세요.",
  };
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>${title} · 설정</title><style>
*{box-sizing:border-box}body{margin:0;background:#f5f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.top{height:58px;background:#fff;border-bottom:1px solid #e5e7eb;display:flex;align-items:center;justify-content:space-between;padding:0 18px;position:sticky;top:0}.top a,.btn,button{display:inline-flex;align-items:center;justify-content:center;min-height:40px;border-radius:12px;border:1px solid #d1d5db;background:#fff;color:#111827;text-decoration:none;font-weight:900;padding:0 13px;cursor:pointer}.primary,button{background:#1d4ed8;color:#fff;border-color:#1d4ed8}.wrap{max-width:840px;margin:0 auto;padding:18px}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:14px 0;box-shadow:0 8px 24px rgba(15,23,42,.055)}label{display:block;font-weight:900;margin:12px 0 6px}input{width:100%;height:44px;border:1px solid #cbd5e1;border-radius:14px;padding:0 12px;font:inherit}.muted{color:#64748b;font-size:13px;line-height:1.6}.ok{background:#dcfce7;color:#166534;border-radius:14px;padding:11px;margin:10px 0}.err{background:#fee2e2;color:#991b1b;border-radius:14px;padding:11px;margin:10px 0}.pill{display:inline-flex;border-radius:999px;padding:6px 10px;font-weight:900;font-size:12px;background:#eff6ff;color:#1d4ed8}.warn{background:#fff7ed;color:#9a3412;border:1px solid #fed7aa;border-radius:14px;padding:12px;line-height:1.6}</style></head><body>${renderUnifiedNav("settings")}<header class="top"><b>설정</b><nav><a href="/?legacy=1">관리자 홈</a> <a href="/app">모바일 입력</a> <a href="/diagnostics">시스템진단</a></nav></header><main class="wrap"><h1>보안 설정</h1>${msg ? `<div class="ok">${escapeHtml(msgMap[msg] || msg)}</div>` : ""}${err ? `<div class="err">${escapeHtml(errMap[err] || err)}</div>` : ""}<section class="card"><h2>관리자 비밀번호</h2><p class="muted">가계부 접속 비밀번호는 정상입니다. 가족/관리자 외 접근을 막기 위한 관리자 보호장치입니다. 단, 비밀번호 저장은 PC가 아니라 운영 서버와 Supabase 클라우드 기준으로 처리합니다.</p><p><span class="pill">${hasDbPassword ? "앱 비밀번호 설정됨" : "Cloudflare 기본 비밀번호 사용 중"}</span></p><form method="post" action="/admin/settings/password"><label>현재 비밀번호</label><input name="current_password" type="password" autocomplete="current-password" required/><label>새 비밀번호</label><input name="new_password" type="password" autocomplete="new-password" minlength="6" required/><label>새 비밀번호 확인</label><input name="confirm_password" type="password" autocomplete="new-password" minlength="6" required/><p><button type="submit">비밀번호 변경</button></p></form><div class="warn"><b>중요</b><br/>이 화면에서 변경한 비밀번호는 안전하게 저장됩니다. 변경 후에는 새 비밀번호로 다시 로그인해 확인하세요.</div></section><section class="card"><h2>공유 설정</h2><p class="muted">공유 기능은 기본 공유와 문구 복사를 우선 제공합니다.</p></section><section class="card"><h2>저장 상태</h2><p class="muted">설정 저장이 정상 처리되는지 화면에서 확인하세요.</p></section></main></body></html>`;
}




