function safeArray(value) {
  return Array.isArray(value) ? value : [];
}

function safeObject(value) {
  return value && typeof value === "object" && !Array.isArray(value) ? value : {};
}

function countObjectArrays(obj) {
  const o = safeObject(obj);
  return Object.values(o).reduce((a, v) => a + (Array.isArray(v) ? v.length : 0), 0);
}

function validateBackupPayloadShape(payload) {
  const errors = [];
  const warnings = [];
  const p = safeObject(payload);
  if (!p || !Object.keys(p).length) errors.push("JSON 객체가 아닙니다.");
  if (p.app !== "kakao-accountbook") warnings.push("app 값이 kakao-accountbook이 아닙니다.");
  if (!String(p.version || "").startsWith("V")) warnings.push("백업 버전 정보가 없습니다.");
  if (!p.exported_at) warnings.push("exported_at 값이 없습니다.");
  if (!safeObject(p.scope).month) warnings.push("백업 기준 월(scope.month)이 없습니다.");
  if (!Array.isArray(p.households)) errors.push("households 배열이 없습니다.");
  if (!Array.isArray(p.transactions)) errors.push("transactions 배열이 없습니다.");
  if (!safeObject(p.household_members) || !Object.keys(safeObject(p.household_members)).length) warnings.push("household_members 정보가 없거나 비어 있습니다.");
  if (!safeObject(p.budgets)) warnings.push("budgets 객체가 없습니다.");
  if (!safeObject(p.recurring)) warnings.push("recurring 객체가 없습니다.");
  if (!safeObject(p.categories)) warnings.push("categories 객체가 없습니다.");

  const transactions = safeArray(p.transactions);
  const missingId = transactions.filter((t) => !safeObject(t).id).length;
  const missingDate = transactions.filter((t) => !safeObject(t).transaction_date).length;
  const badAmount = transactions.filter((t) => !Number.isFinite(Number(safeObject(t).amount))).length;
  if (missingId) warnings.push(`거래 ID가 없는 항목 ${missingId}건`);
  if (missingDate) warnings.push(`거래 날짜가 없는 항목 ${missingDate}건`);
  if (badAmount) warnings.push(`금액이 숫자가 아닌 항목 ${badAmount}건`);

  const counts = {
    households: safeArray(p.households).length,
    transactions: transactions.length,
    members: countObjectArrays(p.household_members),
    budgets: countObjectArrays(p.budgets),
    recurring: countObjectArrays(p.recurring),
    categories: countObjectArrays(p.categories),
  };
  return { ok: errors.length === 0, errors, warnings, counts };
}

function summarizeBackupPayload(payload) {
  const p = safeObject(payload);
  const transactions = safeArray(p.transactions);
  const expense = transactions.filter((t) => safeObject(t).type !== "income").reduce((a, t) => a + Number(safeObject(t).amount || 0), 0);
  const income = transactions.filter((t) => safeObject(t).type === "income").reduce((a, t) => a + Number(safeObject(t).amount || 0), 0);
  const categoryMap = {};
  for (const t of transactions) {
    const row = safeObject(t);
    const c = row.category || "미분류";
    categoryMap[c] = (categoryMap[c] || 0) + Number(row.amount || 0);
  }
  const topCategories = Object.entries(categoryMap).sort((a, b) => b[1] - a[1]).slice(0, 8);
  const byDate = {};
  for (const t of transactions) {
    const row = safeObject(t);
    const d = row.transaction_date || "날짜없음";
    byDate[d] = (byDate[d] || 0) + 1;
  }
  const dateRange = Object.keys(byDate).filter((d) => /^\d{4}-\d{2}-\d{2}$/.test(d)).sort();
  return {
    version: p.version || "",
    exported_at: p.exported_at || "",
    scope: safeObject(p.scope),
    income,
    expense,
    balance: income - expense,
    topCategories,
    firstDate: dateRange[0] || "",
    lastDate: dateRange[dateRange.length - 1] || "",
  };
}

function renderBackupPreviewHtml({ payload = null, validation = null, summary = null, error = "" } = {}) {
  const hasPayload = !!payload;
  const counts = validation?.counts || { households: 0, transactions: 0, members: 0, budgets: 0, recurring: 0, categories: 0 };
  const metricCards = [
    ["가계부", counts.households],
    ["거래", counts.transactions],
    ["참여자", counts.members],
    ["예산", counts.budgets],
    ["고정항목", counts.recurring],
    ["사용자 분류", counts.categories],
  ].map(([k, v]) => `<div class="metric"><span>${escapeHtml(k)}</span><b>${numberWithCommas(v || 0)}</b></div>`).join("");
  const errors = (validation?.errors || []).map((x) => `<li>${escapeHtml(x)}</li>`).join("");
  const warnings = (validation?.warnings || []).map((x) => `<li>${escapeHtml(x)}</li>`).join("");
  const topRows = (summary?.topCategories || []).map(([name, amount]) => `<tr><td>${escapeHtml(name)}</td><td>${numberWithCommas(amount)}원</td></tr>`).join("");
  const statusBox = error ? `<section class="card bad"><h2>파일을 읽지 못했습니다</h2><p>${escapeHtml(error)}</p></section>` : hasPayload ? `<section class="card ${validation.ok ? "good" : "bad"}"><h2>${validation.ok ? "검증 통과" : "검증 실패"}</h2><p>${validation.ok ? "백업 파일 구조가 정상입니다. 아직 복구 적용은 하지 않고 미리보기만 제공합니다." : "필수 구조가 부족합니다. 이 파일은 복구용으로 사용하지 않는 것이 안전합니다."}</p>${errors ? `<h3>오류</h3><ul>${errors}</ul>` : ""}${warnings ? `<h3>주의</h3><ul>${warnings}</ul>` : ""}</section>` : "";
  const summaryHtml = hasPayload ? `<section class="grid">${metricCards}</section><section class="card"><h2>백업 요약</h2><div class="summaryGrid"><div><span>백업 버전</span><b>${escapeHtml(summary.version || "미상")}</b></div><div><span>생성 시각</span><b>${escapeHtml(summary.exported_at || "미상")}</b></div><div><span>기간</span><b>${escapeHtml(summary.firstDate || "-")} ~ ${escapeHtml(summary.lastDate || "-")}</b></div><div><span>수입</span><b>${numberWithCommas(summary.income || 0)}원</b></div><div><span>지출</span><b>${numberWithCommas(summary.expense || 0)}원</b></div><div><span>잔액</span><b>${numberWithCommas(summary.balance || 0)}원</b></div></div></section><section class="card"><h2>상위 분류</h2><table><thead><tr><th>분류</th><th>금액</th></tr></thead><tbody>${topRows || `<tr><td colspan="2">표시할 분류가 없습니다.</td></tr>`}</tbody></table></section>` : "";
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>백업 미리보기</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1120px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#111827,#0f766e);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.card.good{border-color:#86efac;background:#f0fdf4}.card.bad{border-color:#fecaca;background:#fef2f2}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:25px;margin-top:6px}.upload{display:grid;gap:10px}.upload input[type=file]{padding:16px;border:2px dashed #cbd5e1;border-radius:18px;background:#f8fafc}.btn,.upload button{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border:0;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px;cursor:pointer}.btn.light{background:#eff6ff;color:#1e3a8a}.summaryGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:10px}.summaryGrid div{background:#f8fafc;border:1px solid #e5e7eb;border-radius:16px;padding:12px}.summaryGrid span{display:block;color:#64748b;font-size:13px}.summaryGrid b{display:block;margin-top:4px}table{width:100%;border-collapse:collapse}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left}.warn{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}@media(max-width:640px){.wrap{padding:12px}.hero h1{font-size:24px}}</style></head><body>${renderUnifiedNav("backup")}<main class="wrap"><section class="hero"><h1>백업 미리보기</h1><p>내려받은 JSON 백업 파일을 복구하기 전에 구조와 건수를 확인합니다. 이 화면은 DB에 아무것도 저장하지 않습니다.</p><p><a class="btn light" href="/backup">백업센터로 돌아가기</a></p></section><section class="card"><h2>JSON 백업 파일 선택</h2><p class="warn">민감한 데이터가 포함될 수 있으므로 본인 백업 파일만 확인하세요. 현재 단계에서는 복구 자동 적용을 하지 않습니다.</p><form class="upload" method="post" action="/backup/preview" enctype="multipart/form-data"><input type="file" name="backup_file" accept="application/json,.json" required/><button type="submit">백업 파일 검증/미리보기</button></form></section>${statusBox}${summaryHtml}</main></body></html>`;
}

async function handleBackupPreviewPage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  return htmlResponse(renderBackupPreviewHtml());
}

async function handleBackupPreviewPost(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  try {
    const form = await request.formData();
    const file = form.get("backup_file");
    if (!file || typeof file.text !== "function") {
      return htmlResponse(renderBackupPreviewHtml({ error: "업로드된 JSON 파일이 없습니다." }), 400);
    }
    const raw = await file.text();
    if (raw.length > 8 * 1024 * 1024) {
      return htmlResponse(renderBackupPreviewHtml({ error: "파일이 너무 큽니다. 8MB 이하 JSON만 먼저 확인하세요." }), 400);
    }
    const payload = JSON.parse(raw);
    const validation = validateBackupPayloadShape(payload);
    const summary = summarizeBackupPayload(payload);
    return htmlResponse(renderBackupPreviewHtml({ payload, validation, summary }), validation.ok ? 200 : 400);
  } catch (err) {
    return htmlResponse(renderBackupPreviewHtml({ error: `JSON을 해석하지 못했습니다: ${safeError(err)}` }), 400);
  }
}




function normalizeComparableText(value) {
  return String(value || "").trim();
}

function transactionComparable(row) {
  const r = safeObject(row);
  return {
    type: normalizeTransactionType(r.type),
    transaction_date: String(r.transaction_date || "").slice(0, 10),
    amount: Number(r.amount || 0),
    category: normalizeComparableText(r.category),
    memo: normalizeComparableText(r.memo || r.raw_text),
    payment_method: normalizeComparableText(r.payment_method),
    user_id: normalizeComparableText(r.user_id),
  };
}

function transactionSignature(row) {
  const r = transactionComparable(row);
  return [r.type, r.transaction_date, r.amount, r.category, r.memo, r.payment_method].join("|");
}

function transactionDiffFields(a, b) {
  const aa = transactionComparable(a);
  const bb = transactionComparable(b);
  const fields = ["type", "transaction_date", "amount", "category", "memo", "payment_method", "user_id"];
  return fields.filter((f) => String(aa[f]) !== String(bb[f]));
}

function compareBackupTransactions(backupRows, currentRows) {
  const backup = safeArray(backupRows);
  const current = safeArray(currentRows);
  const currentById = new Map();
  const currentBySignature = new Map();
  for (const row of current) {
    const r = safeObject(row);
    if (r.id) currentById.set(String(r.id), r);
    const sig = transactionSignature(r);
    if (!currentBySignature.has(sig)) currentBySignature.set(sig, []);
    currentBySignature.get(sig).push(r);
  }

  const backupIds = new Set();
  const backupSigs = new Set();
  const sameId = [];
  const contentDuplicates = [];
  const conflicts = [];
  const newCandidates = [];

  for (const row of backup) {
    const r = safeObject(row);
    const id = String(r.id || "");
    const sig = transactionSignature(r);
    if (id) backupIds.add(id);
    backupSigs.add(sig);
    if (id && currentById.has(id)) {
      const cur = currentById.get(id);
      const diff = transactionDiffFields(r, cur);
      if (diff.length) conflicts.push({ backup: r, current: cur, diff });
      else sameId.push(r);
    } else if (currentBySignature.has(sig)) {
      contentDuplicates.push({ backup: r, current: currentBySignature.get(sig)[0] });
    } else {
      newCandidates.push(r);
    }
  }

  const currentOnly = current.filter((row) => {
    const r = safeObject(row);
    const id = String(r.id || "");
    const sig = transactionSignature(r);
    return (!id || !backupIds.has(id)) && !backupSigs.has(sig);
  });

  const risk = conflicts.length ? "danger" : (sameId.length || contentDuplicates.length) ? "warn" : "good";
  return {
    risk,
    counts: {
      backup: backup.length,
      current: current.length,
      same_id: sameId.length,
      same_content: contentDuplicates.length,
      conflicts: conflicts.length,
      new_candidates: newCandidates.length,
      current_only: currentOnly.length,
    },
    sameId,
    contentDuplicates,
    conflicts,
    newCandidates,
    currentOnly,
  };
}

function renderBackupCompareRows(rows, type = "new") {
  const arr = safeArray(rows).slice(0, 30);
  if (!arr.length) return `<tr><td colspan="6">표시할 항목이 없습니다.</td></tr>`;
  return arr.map((item) => {
    const row = safeObject(item.backup || item);
    const diff = Array.isArray(item.diff) && item.diff.length ? ` · 차이: ${item.diff.join(", ")}` : "";
    return `<tr><td>${escapeHtml(String(row.transaction_date || ""))}</td><td>${row.type === "income" ? "수입" : "지출"}</td><td>${numberWithCommas(row.amount || 0)}원</td><td>${escapeHtml(row.category || "")}</td><td>${escapeHtml(row.memo || row.raw_text || "")}</td><td>${escapeHtml(row.id || "")}${escapeHtml(diff)}</td></tr>`;
  }).join("");
}

function renderBackupCompareHtml({ payload = null, validation = null, summary = null, compare = null, month = "", householdId = "", households = [], error = "" } = {}) {
  const hasResult = !!compare;
  const riskLabel = compare?.risk === "danger" ? "충돌 위험" : compare?.risk === "warn" ? "중복 가능성" : "안전";
  const riskText = compare?.risk === "danger" ? "같은 ID인데 내용이 다른 거래가 있습니다. 자동 복구/가져오기는 위험합니다." : compare?.risk === "warn" ? "이미 존재하는 거래가 있어 중복 저장 위험이 있습니다. 가져오기 전에 확인이 필요합니다." : "현재 데이터와 충돌·중복 위험이 낮습니다.";
  const cards = compare ? [
    ["백업 거래", compare.counts.backup],
    ["현재 거래", compare.counts.current],
    ["동일 ID", compare.counts.same_id],
    ["동일 내용", compare.counts.same_content],
    ["충돌", compare.counts.conflicts],
    ["신규 후보", compare.counts.new_candidates],
    ["현재만 있음", compare.counts.current_only],
  ].map(([label, value]) => `<div class="metric"><span>${escapeHtml(label)}</span><b>${numberWithCommas(value || 0)}</b></div>`).join("") : "";
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === householdId ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  const errorBox = error ? `<section class="card bad"><h2>비교 실패</h2><p>${escapeHtml(error)}</p></section>` : "";
  const validationBox = validation ? `<section class="card ${validation.ok ? "good" : "bad"}"><h2>백업 파일 구조: ${validation.ok ? "정상" : "확인 필요"}</h2>${validation.errors?.length ? `<h3>오류</h3><ul>${validation.errors.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}${validation.warnings?.length ? `<h3>주의</h3><ul>${validation.warnings.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}</section>` : "";
  const resultHtml = hasResult ? `<section class="card ${compare.risk}"><h2>비교 결과: ${escapeHtml(riskLabel)}</h2><p>${escapeHtml(riskText)}</p></section><section class="grid">${cards}</section><section class="card"><h2>충돌 항목</h2><p class="note">같은 ID인데 백업과 현재 데이터 내용이 다른 항목입니다.</p><table><thead><tr><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>ID/차이</th></tr></thead><tbody>${renderBackupCompareRows(compare.conflicts, "conflict")}</tbody></table></section><section class="card"><h2>신규 후보</h2><p class="note">현재 데이터에 없어 보이는 백업 거래입니다. 아직 DB에 저장하지 않습니다.</p><table><thead><tr><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>ID</th></tr></thead><tbody>${renderBackupCompareRows(compare.newCandidates, "new")}</tbody></table></section><section class="card"><h2>중복 가능 항목</h2><p class="note">ID 또는 내용 기준으로 이미 존재하는 거래입니다.</p><table><thead><tr><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>ID</th></tr></thead><tbody>${renderBackupCompareRows([...compare.sameId.slice(0, 15), ...compare.contentDuplicates.slice(0, 15)], "dup")}</tbody></table></section>` : "";
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>백업 비교</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1140px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#111827,#7c2d12);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.card.good{border-color:#86efac;background:#f0fdf4}.card.warn{border-color:#fde68a;background:#fffbeb}.card.danger,.card.bad{border-color:#fecaca;background:#fef2f2}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:25px;margin-top:6px}.upload{display:grid;grid-template-columns:1fr 160px 170px;gap:10px}.upload input,.upload select,.upload button{min-height:42px;border:1px solid #d1d5db;border-radius:13px;padding:0 12px;background:#fff;font:inherit}.upload input[type=file]{padding:10px}.upload button{background:#111827;color:#fff;font-weight:1000;cursor:pointer}.btn{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px}.btn.light{background:#eff6ff;color:#1e3a8a}.note{color:#64748b;line-height:1.55}table{width:100%;border-collapse:collapse;background:#fff}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left;font-size:13px;vertical-align:top}.warnBox{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}@media(max-width:760px){.wrap{padding:12px}.hero h1{font-size:24px}.upload{grid-template-columns:1fr}.card{overflow-x:auto}table{min-width:760px}}</style></head><body>${renderUnifiedNav("backup", { month, householdId })}<main class="wrap"><section class="hero"><h1>백업 비교/중복 위험 분석</h1><p>백업 JSON을 현재 Supabase 데이터와 비교해, 복구 전에 중복·충돌 위험을 확인합니다. 이 화면은 DB에 아무것도 저장하지 않습니다.</p><p><a class="btn light" href="/backup">백업센터</a> <a class="btn light" href="/backup/preview">백업 미리보기</a></p></section><section class="card"><h2>백업 파일 비교</h2><p class="warnBox">복구 자동 적용 전 단계입니다. 같은 ID, 같은 내용, 충돌 항목, 신규 후보만 분석합니다.</p><form class="upload" method="post" action="/backup/compare" enctype="multipart/form-data"><input type="file" name="backup_file" accept="application/json,.json" required/><select name="household_id"><option value="">백업 기준 사용/전체</option>${householdOptions}</select><button type="submit">비교 분석</button></form></section>${errorBox}${validationBox}${resultHtml}</main></body></html>`;
}

async function handleBackupComparePage(request, env, url) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  const households = await fetchAdminHouseholds(env);
  const householdId = url.searchParams.get("household_id") || households[0]?.id || "";
  return htmlResponse(renderBackupCompareHtml({ households, householdId, month: currentMonthKst() }));
}

async function handleBackupComparePost(request, env) {
  if (!(await verifyAdminSession(request, env))) return redirectResponse("/?legacy=1");
  let households = [];
  try { households = await fetchAdminHouseholds(env); } catch (_) {}
  try {
    const form = await request.formData();
    const file = form.get("backup_file");
    if (!file || typeof file.text !== "function") {
      return htmlResponse(renderBackupCompareHtml({ households, error: "업로드된 JSON 파일이 없습니다." }), 400);
    }
    const raw = await file.text();
    if (raw.length > 8 * 1024 * 1024) {
      return htmlResponse(renderBackupCompareHtml({ households, error: "파일이 너무 큽니다. 8MB 이하 JSON만 먼저 비교하세요." }), 400);
    }
    const payload = JSON.parse(raw);
    const validation = validateBackupPayloadShape(payload);
    const summary = summarizeBackupPayload(payload);
    const scope = safeObject(payload.scope);
    const month = validMonth(scope.month) || currentMonthKst();
    const formHouseholdId = String(form.get("household_id") || "").trim();
    const householdId = formHouseholdId || String(scope.household_id || "").trim();
    if (!validation.ok) {
      return htmlResponse(renderBackupCompareHtml({ payload, validation, summary, households, month, householdId }), 400);
    }
    const currentRows = await fetchAdminRows(env, { month, householdId, type: "all" });
    const compare = compareBackupTransactions(safeArray(payload.transactions), currentRows);
    return htmlResponse(renderBackupCompareHtml({ payload, validation, summary, compare, households, month, householdId }));
  } catch (err) {
    return htmlResponse(renderBackupCompareHtml({ households, error: `비교 중 오류가 발생했습니다: ${safeError(err)}` }), 400);
  }
}


function renderImportCandidateRows(rows = []) {
  const arr = safeArray(rows).slice(0, 200);
  if (!arr.length) return `<tr><td colspan="8">가져오기 후보가 없습니다.</td></tr>`;
  return arr.map((row, idx) => {
    const r = safeObject(row);
    const key = stableShortHash(JSON.stringify(transactionComparable(r)));
    return `<tr data-candidate-row="1"><td><input class="candidateCheck" type="checkbox" name="candidate_key" value="${escapeHtml(key)}" data-amount="${escapeHtml(r.amount || 0)}" data-type="${escapeHtml(r.type || "expense")}"/></td><td>${idx + 1}</td><td>${escapeHtml(String(r.transaction_date || ""))}</td><td>${r.type === "income" ? "수입" : "지출"}</td><td>${numberWithCommas(r.amount || 0)}원</td><td>${escapeHtml(r.category || "")}</td><td>${escapeHtml(r.memo || r.raw_text || "")}</td><td>${escapeHtml(r.payment_method || "")}</td></tr>`;
  }).join("");
}

function renderImportCandidateHiddenJson(rows = []) {
  const safeRows = safeArray(rows).slice(0, 200).map((r) => transactionComparable(r));
  return escapeHtml(JSON.stringify(safeRows));
}

function renderBackupCandidateSelectHtml({ payload = null, validation = null, compare = null, month = "", householdId = "", households = [], error = "" } = {}) {
  const candidates = safeArray(compare?.newCandidates);
  const conflictCount = Number(compare?.counts?.conflicts || 0);
  const duplicateCount = Number(compare?.counts?.same_id || 0) + Number(compare?.counts?.same_content || 0);
  const householdOptions = households.map((h) => `<option value="${escapeHtml(h.id)}" ${h.id === householdId ? "selected" : ""}>${escapeHtml(h.name)}</option>`).join("");
  const errorBox = error ? `<section class="card bad"><h2>후보 분석 실패</h2><p>${escapeHtml(error)}</p></section>` : "";
  const validationBox = validation ? `<section class="card ${validation.ok ? "good" : "bad"}"><h2>백업 구조: ${validation.ok ? "정상" : "확인 필요"}</h2>${validation.errors?.length ? `<h3>오류</h3><ul>${validation.errors.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}${validation.warnings?.length ? `<h3>주의</h3><ul>${validation.warnings.map((x) => `<li>${escapeHtml(x)}</li>`).join("")}</ul>` : ""}</section>` : "";
  const summary = compare ? `<section class="grid"><div class="metric"><span>신규 후보</span><b>${numberWithCommas(candidates.length)}</b></div><div class="metric"><span>충돌</span><b>${numberWithCommas(conflictCount)}</b></div><div class="metric"><span>중복 가능</span><b>${numberWithCommas(duplicateCount)}</b></div><div class="metric"><span>현재만 있음</span><b>${numberWithCommas(compare.counts.current_only || 0)}</b></div></section>` : "";
  const riskBox = compare ? `<section class="card ${conflictCount ? "bad" : duplicateCount ? "warn" : "good"}"><h2>${conflictCount ? "충돌 항목 확인 필요" : duplicateCount ? "중복 가능성 있음" : "신규 후보 선택 가능"}</h2><p>${conflictCount ? "같은 ID인데 내용이 다른 항목이 있어 자동 가져오기를 진행하면 안 됩니다." : "아래 신규 후보 중 실제로 가져올 항목을 체크해 가져오기 계획만 만들 수 있습니다. 아직 DB에는 저장하지 않습니다."}</p></section>` : "";
  const candidateBox = compare ? `<section class="card"><div class="cardTitle"><div><h2>가져오기 후보 선택</h2><p class="note">현재 데이터에 없어 보이는 거래만 표시합니다. 체크박스는 가져오기 계획 생성용이며, DB 저장은 하지 않습니다.</p></div><div class="actions"><button type="button" class="btn light" onclick="setCandidateChecks(true)">전체 선택</button><button type="button" class="btn light" onclick="setCandidateChecks(false)">선택 해제</button><button type="button" class="btn green" onclick="downloadImportPlan()">선택 계획 JSON 저장</button></div></div><div class="selectedBar"><b id="candidateSelectedCount">0건 선택</b><span id="candidateSelectedAmount">0원</span></div><input type="hidden" id="candidateJson" value="${renderImportCandidateHiddenJson(candidates)}"/><div class="tableWrap"><table><thead><tr><th>선택</th><th>#</th><th>날짜</th><th>유형</th><th>금액</th><th>분류</th><th>메모</th><th>수단</th></tr></thead><tbody>${renderImportCandidateRows(candidates)}</tbody></table></div>${candidates.length > 200 ? `<p class="note">후보가 많아 상위 200건만 표시합니다.</p>` : ""}</section>` : "";
  return `<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>가져오기 후보 선택</title><style>body{margin:0;background:#f6f7fb;color:#111827;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans KR",sans-serif}.wrap{max-width:1160px;margin:0 auto;padding:18px}.hero{background:linear-gradient(135deg,#0f172a,#14532d);color:#fff;border-radius:26px;padding:22px;margin:14px 0;box-shadow:0 18px 40px rgba(15,23,42,.18)}.hero h1{margin:0;font-size:30px}.hero p{line-height:1.6;opacity:.9}.card{background:#fff;border:1px solid #e5e7eb;border-radius:22px;padding:18px;margin:12px 0;box-shadow:0 10px 28px rgba(15,23,42,.055)}.card.good{border-color:#86efac;background:#f0fdf4}.card.warn{border-color:#fde68a;background:#fffbeb}.card.bad{border-color:#fecaca;background:#fef2f2}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.metric{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:15px}.metric span{display:block;color:#64748b}.metric b{display:block;font-size:25px;margin-top:6px}.upload{display:grid;grid-template-columns:1fr 160px 170px;gap:10px}.upload input,.upload select,.upload button{min-height:42px;border:1px solid #d1d5db;border-radius:13px;padding:0 12px;background:#fff;font:inherit}.upload input[type=file]{padding:10px}.upload button,.btn{display:inline-flex;align-items:center;justify-content:center;min-height:42px;border:0;border-radius:13px;background:#111827;color:#fff;text-decoration:none;font-weight:1000;padding:0 13px;cursor:pointer}.btn.light{background:#eff6ff;color:#1e3a8a}.btn.green{background:#059669;color:#fff}.note{color:#64748b;line-height:1.55}.warnBox{background:#fff7ed;border:1px solid #fed7aa;border-radius:16px;padding:12px;color:#9a3412;line-height:1.55}.cardTitle{display:flex;justify-content:space-between;gap:12px;align-items:flex-start;flex-wrap:wrap}.actions{display:flex;gap:8px;flex-wrap:wrap}.selectedBar{display:flex;gap:10px;align-items:center;flex-wrap:wrap;margin:10px 0;padding:12px;border-radius:16px;background:#eff6ff;color:#1e3a8a;font-weight:1000}.tableWrap{overflow-x:auto}table{width:100%;border-collapse:collapse;background:#fff;min-width:860px}th,td{border-bottom:1px solid #e5e7eb;padding:10px;text-align:left;font-size:13px;vertical-align:top}.candidateCheck{width:20px;height:20px}@media(max-width:760px){.wrap{padding:12px}.hero h1{font-size:24px}.upload{grid-template-columns:1fr}.card{overflow-x:auto}}</style></head><body>${renderUnifiedNav("backup", { month, householdId })}<main class="wrap"><section class="hero"><h1>가져오기 후보 선택</h1><p>백업 파일에서 현재 데이터에 없는 거래 후보만 골라 가져오기 계획을 만듭니다. 이 단계도 DB에 아무것도 저장하지 않습니다.</p><p><a class="btn light" href="/backup">백업센터</a> <a class="btn light" href="/backup/compare">백업 비교</a></p></section><section class="card"><h2>백업 파일 분석</h2><p class="warnBox">복구 자동 적용 전 단계입니다. 선택 결과는 JSON 계획 파일로만 저장되며, Supabase 데이터는 변경하지 않습니다.</p><form class="upload" method="post" action="/backup/select" enctype="multipart/form-data"><input type="file" name="backup_file" accept="application/json,.json" required/><select name="household_id"><option value="">백업 기준 사용/전체</option>${householdOptions}</select><button type="submit">후보 분석</button></form></section>${errorBox}${validationBox}${summary}${riskBox}${candidateBox}</main><script>(function(){function money(n){n=Number(n||0);return n.toLocaleString('ko-KR')+'원'}window.setCandidateChecks=function(v){document.querySelectorAll('.candidateCheck').forEach(function(x){x.checked=!!v});updateCandidateSelection()};function updateCandidateSelection(){var count=0, amount=0;document.querySelectorAll('.candidateCheck').forEach(function(x){if(x.checked){count++;if((x.getAttribute('data-type')||'expense')==='income')amount-=Number(x.getAttribute('data-amount')||0);else amount+=Number(x.getAttribute('data-amount')||0)}});var c=document.getElementById('candidateSelectedCount');var a=document.getElementById('candidateSelectedAmount');if(c)c.textContent=count+'건 선택';if(a)a.textContent='순지출 기준 '+money(amount)}document.querySelectorAll('.candidateCheck').forEach(function(x){x.addEventListener('change',updateCandidateSelection)});window.downloadImportPlan=function(){var raw=document.getElementById('candidateJson');var rows=[];try{rows=JSON.parse(raw?raw.value:'[]')}catch(e){rows=[]}var selected=[];document.querySelectorAll('.candidateCheck').forEach(function(x,idx){if(x.checked&&rows[idx])selected.push(rows[idx])});var payload={app:'kakao-accountbook',version:'V19.8-BUDGET-ALERT',created_at:new Date().toISOString(),mode:'candidate_plan_only_no_db_write',selected_count:selected.length,selected:selected};var blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'});var a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='accountbook_import_candidate_plan.json';document.body.appendChild(a);a.click();setTimeout(function(){URL.revokeObjectURL(a.href);a.remove()},1000)};updateCandidateSelection();})();</script></body></html>`;
}

