async function handleMyBackupCsv(request, env, url) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return redirectResponse("/my");
  const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
  const { selected } = await getMySelectedHousehold(env, userId, url.searchParams.get("household_id") || "");
  if (!selected) return redirectResponse("/my?err=no_household");
  const rows = await fetchAdminRows(env, { month, householdId: selected.id, type: "all" });
  const csv = buildReadableTransactionsCsv(rows);
  const file = `accountbook_${month}_${String(selected.name || "backup").replace(/[^\w가-힣-]+/g, "_")}.csv`;
  return csvResponse(csv, file);
}

async function handleMyImport(request, env) {
  const userId = await verifyUserSession(request, env);
  if (!userId) return redirectResponse("/my");
  const form = await request.formData();
  const householdId = String(form.get("household_id") || "").trim();
  const month = validMonth(String(form.get("month") || "")) || currentMonthKst();
  const { selected } = await getMySelectedHousehold(env, userId, householdId);
  if (!selected) return redirectResponse("/my?err=no_household");
  if (!canWriteMyHousehold(selected.role)) return redirectResponse(`/my/backup?household_id=${encodeURIComponent(selected.id)}&month=${encodeURIComponent(month)}&err=write_not_allowed`);
  let csvText = String(form.get("csv_text") || "");
  const file = form.get("csv_file");
  if (file && typeof file.text === "function") {
    const t = await file.text();
    if (String(t || "").trim()) csvText = t;
  }
  if (!String(csvText || "").trim()) return redirectResponse(`/my/backup?household_id=${encodeURIComponent(selected.id)}&month=${encodeURIComponent(month)}&err=empty_import`);
  const allObjects = csvRowsToObjects(csvText).slice(0, 500);
  const importLimit = Math.min(500, Math.max(10, Number(env.MY_IMPORT_LIMIT || 120)));
  const objects = allObjects.slice(0, importLimit);
  let imported = 0, skipped = Math.max(0, allObjects.length - objects.length), failed = 0;
  if (allObjects.length > objects.length) rememberDuplicateEvent({ kind: "bulk_limited", source: "my_import", household_id: selected.id, user_id: userId, detail: `${allObjects.length} requested, ${objects.length} processed`, path: "/my/import", method: "POST" });
  const skipDuplicates = form.get("skip_duplicates") === "1";
  for (const obj of objects) {
    const row = normalizeImportTransaction(obj, selected.id, userId);
    if (!row) { failed += 1; continue; }
    try {
      if (skipDuplicates && await findExactDuplicateTransaction(env, row)) { skipped += 1; continue; }
      await createManualTransaction(env, row);
      imported += 1;
    } catch (err) {
      failed += 1;
    }
  }
  return redirectResponse(`/my/backup?household_id=${encodeURIComponent(selected.id)}&month=${encodeURIComponent(month)}&msg=imported_${imported}_skipped_${skipped}_failed_${failed}`);
}


function recurringDateForMonth(month = currentMonthKst(), day = 1) {
  const ym = validMonth(month) || currentMonthKst();
  const y = Number(ym.slice(0, 4));
  const m = Number(ym.slice(5, 7));
  const last = new Date(y, m, 0).getDate();
  const d = Math.min(last, Math.max(1, Number(day || 1)));
  return `${ym}-${String(d).padStart(2, "0")}`;
}

async function findRecurringAutoDuplicate(env, row = {}) {
  if (!row.household_id || !row.transaction_date || !row.amount) return null;
  const params = new URLSearchParams();
  params.set("select", "id,household_id,user_id,type,amount,category,memo,payment_method,transaction_date,source,raw_text,created_at");
  params.set("household_id", `eq.${row.household_id}`);
  params.set("transaction_date", `eq.${row.transaction_date}`);
  params.set("type", `eq.${row.type === "income" ? "income" : "expense"}`);
  params.set("amount", `eq.${Math.round(Number(row.amount || 0))}`);
  params.set("source", "eq.recurring_auto");
  params.set("limit", "30");
  let rows = [];
  try {
    rows = await supabase(env, `/rest/v1/transactions?${params.toString()}`, { method: "GET" }) || [];
  } catch (err) {
    rememberOpsEvent({ kind: "duplicate_check_error", severity: "warn", path: "/rest/v1/transactions", method: "GET", detail: safeError(err) });
    return null;
  }
  const norm = (v) => normalizeText(v || "");
  return rows.find((r) => norm(r.memo) === norm(row.memo) && norm(r.category) === norm(row.category) && norm(r.payment_method) === norm(row.payment_method)) || null;
}

async function runRecurringAutoApply(env, opts = {}) {
  const today = opts.today || formatDate(nowKstDate());
  const month = validMonth(opts.month) || String(today).slice(0, 7) || currentMonthKst();
  const currentDay = Number(String(today).slice(8, 10) || "1");
  const households = await supabase(env, "/rest/v1/households?select=id,name,created_at&order=created_at.asc", { method: "GET" }) || [];
  let scanned = 0, applied = 0, skipped = 0, failed = 0;
  for (const household of safeArray(households)) {
    const householdId = household.id;
    if (!householdId) continue;
    const items = await fetchRecurring(env, householdId);
    for (const r of safeArray(items)) {
      if (r.is_active === false || String(r.is_active) === "false") { skipped++; continue; }
      scanned++;
      if (String(r.last_applied_month || "") === month) { skipped++; continue; }
      const dueDay = Math.min(31, Math.max(1, Number(r.day_of_month || 1)));
      if (currentDay < dueDay) { skipped++; continue; }
      const txDate = recurringDateForMonth(month, dueDay);
      const row = {
        household_id: householdId,
        user_id: r.user_id || "",
        type: r.type === "income" ? "income" : "expense",
        amount: Math.max(0, Math.round(Number(r.amount || 0))),
        category: r.category || (r.type === "income" ? "정기수입" : "정기지출"),
        memo: r.memo || r.category || "정기지출",
        payment_method: r.payment_method || "",
        transaction_date: txDate,
        source: "recurring_auto",
        raw_text: `recurring:${r.id || ""}:${month}`,
      };
      if (!row.amount) { failed++; continue; }
      try {
        const dup = await findRecurringAutoDuplicate(env, row);
        if (!dup) await createManualTransaction(env, row);
        await optionalSupabase(env, `/rest/v1/accountbook_recurring?id=eq.${encodeURIComponent(r.id)}`, { method: "PATCH", headers: { Prefer: "return=minimal" }, body: JSON.stringify({ last_applied_month: month }) }, null);
        applied++;
      } catch (err) {
        failed++;
      }
    }
  }
  return { ok: true, month, today, households: safeArray(households).length, scanned, applied, skipped, failed };
}

async function handleRecurringCronApply(request, env, url) {
  const adminOk = await verifyAdminSession(request, env);
  const keyOk = env.CRON_SECRET && url.searchParams.get("key") === env.CRON_SECRET;
  if (!adminOk && !keyOk) return jsonResponse({ ok: false, error: "unauthorized" }, 401);
  const result = await runRecurringAutoApply(env, { month: validMonth(url.searchParams.get("month")) || currentMonthKst(), today: url.searchParams.get("today") || formatDate(nowKstDate()) });
  return jsonResponse(result);
}

function mySettingsLocation(month = currentMonthKst(), householdId = "", extra = {}) {
  const qs = new URLSearchParams();
  qs.set("month", validMonth(month) || currentMonthKst());
  if (householdId) qs.set("household_id", householdId);
  for (const [k, v] of Object.entries(extra || {})) if (v !== undefined && v !== null && String(v) !== "") qs.set(k, String(v));
  return `/my/settings?${qs.toString()}`;
}


