function parseKakaoCreateKind(text = "") {
  const t = normalizeText(text).replace(/^가계부 종류\s*/, "");
  const map = {
    "가족 생활비": "가족 생활비",
    "부부 커플": "부부·커플",
    "모임 회비": "모임 회비",
    "여행 경비": "여행 경비",
    "직접 입력": "직접 입력",
  };
  return map[t] || "";
}

function suggestedHouseholdName(kind = "", nickname = "") {
  if (kind === "가족 생활비") return "우리집 생활비";
  if (kind === "부부·커플") return "우리 둘 가계부";
  if (kind === "모임 회비") return "우리 모임 회비";
  if (kind === "여행 경비") return "우리 여행 경비";
  return `${nickname || "우리"} 가계부`;
}

function sanitizeHouseholdNameInput(text = "") {
  const t = normalizeText(text).replace(/^(가계부 이름|이름|제목)\s*/, "").trim();
  if (t.length < 2 || t.length > 40) return "";
  if (isKakaoGuidedCommand(t) || parseAmountValue(t) > 0) return "";
  return t.slice(0, 40);
}

function parseBareInviteCode(text = "") {
  const t = normalizeText(text).replace(/^(초대코드|코드)\s*/, "").trim();
  return /^[A-Z0-9]{5,12}$/i.test(t) ? t.toUpperCase() : "";
}

function normalizeBudgetCategoryInput(value = "") {
  const raw = normalizeText(value)
    .replace(/^예산 카테고리\s*/, "")
    .replace(/\s*예산$/, "")
    .trim();
  if (/^(전체|전체 월|월 전체|총|총액)$/.test(raw)) return "__total";
  const aliases = {
    "교통비": "교통", "병원비": "의료/병원", "의료": "의료/병원", "교육비": "교육/학습",
    "문화 여가": "문화/여가", "여가": "문화/여가", "카페 간식": "카페/간식",
    "주거 월세": "주거/월세", "가족 용돈": "가족/용돈", "세금 수수료": "세금/수수료",
  };
  return aliases[raw] || raw;
}

function parseBudgetMonthHint(text = "") {
  const t = normalizeText(text);
  if (/다음달|다음 달/.test(t)) return shiftMonthString(currentMonthKst(), 1);
  if (/지난달|지난 달|저번달|저번 달/.test(t)) return shiftMonthString(currentMonthKst(), -1);
  const m = t.match(/(?:20(\d{2})년\s*)?(\d{1,2})월/);
  if (m) {
    const year = m[1] ? Number(`20${m[1]}`) : Number(currentMonthKst().slice(0, 4));
    const month = Number(m[2]);
    if (month >= 1 && month <= 12) return `${year}-${String(month).padStart(2, "0")}`;
  }
  return currentMonthKst();
}

function parseDirectBudgetSetCommand(text = "") {
  const t = normalizeText(text);
  const m = t.match(/^(?:(이번달|이번 달|다음달|다음 달|지난달|지난 달|저번달|저번 달|(?:20\d{2}년\s*)?\d{1,2}월)\s*)?(.{1,35}?)\s*예산\s*(?:설정|저장|등록)\s+(.+)$/i);
  if (!m) return null;
  const amount = parseAmountValue(m[3]);
  if (!amount) return null;
  return {
    month: parseBudgetMonthHint(m[1] || ""),
    category: normalizeBudgetCategoryInput(m[2]),
    amount: Math.round(amount),
  };
}

async function resolveBudgetCategoryName(env, householdId = "", input = "") {
  const category = normalizeBudgetCategoryInput(input);
  if (!category || category === "직접 입력") return "";
  if (category === "__total") return category;
  const custom = await fetchCustomCategories(env, householdId);
  const options = [...DEFAULT_CATEGORIES.filter((x) => !["급여","상여/보너스","용돈수입","환급","이자배당","부업/매출"].includes(x)), ...custom.map((x) => x.name).filter(Boolean)];
  const found = options.find((x) => normalizeText(x) === normalizeText(category));
  return found || "";
}

async function saveKakaoBudget(env, householdId = "", month = currentMonthKst(), category = "", amount = 0) {
  return upsertMyBudgetRow(env, householdId, validMonth(month) || currentMonthKst(), category, amount);
}

async function copyKakaoBudgetsFromPreviousMonth(env, householdId = "", month = currentMonthKst()) {
  const previous = shiftMonthString(month, -1);
  const rows = await fetchBudgets(env, householdId, previous);
  const copyRows = safeArray(rows).filter((r) => Number(r.amount || 0) > 0);
  for (const row of copyRows) await saveKakaoBudget(env, householdId, month, String(row.category || ""), Number(row.amount || 0));
  return { previous, count: copyRows.length };
}

async function getHouseholdById(env, householdId = "") {
  if (!householdId) return null;
  const rows = await supabase(env, `/rest/v1/households?id=eq.${encodeURIComponent(householdId)}&select=id,name,invite_code&limit=1`, { method: "GET" }) || [];
  return rows[0] || null;
}

function parseKakaoSummaryRange(text = "") {
  let t = normalizeText(text);
  const natural = t.match(/^(오늘|어제|이번주|이번 주|지난주|지난 주|이번달|이번 달|지난달|지난 달)\s*(?:얼마\s*썼어|얼마\s*썼지|얼마\s*썼나|지출\s*알려줘|쓴\s*돈|사용\s*금액|지출\s*현황)$/);
  if (natural) t = `${natural[1]} 요약`;
  if (!/(요약|현황|통계)$/.test(t) && !/^(오늘|어제|이번주|이번 주|지난주|지난 주|이번달|이번 달|지난달|지난 달)$/.test(t)) return null;
  const now = nowKstDate();
  let start = null, end = null, label = "";
  if (/오늘/.test(t)) {
    start = new Date(now.getFullYear(), now.getMonth(), now.getDate()); end = addDays(start, 1); label = "오늘";
  } else if (/어제/.test(t)) {
    end = new Date(now.getFullYear(), now.getMonth(), now.getDate()); start = addDays(end, -1); label = "어제";
  } else if (/지난\s*주/.test(t)) {
    const dow = (now.getDay() + 6) % 7; const thisMonday = addDays(new Date(now.getFullYear(), now.getMonth(), now.getDate()), -dow);
    end = thisMonday; start = addDays(thisMonday, -7); label = "지난 주";
  } else if (/이번\s*주/.test(t)) {
    const dow = (now.getDay() + 6) % 7; start = addDays(new Date(now.getFullYear(), now.getMonth(), now.getDate()), -dow); end = addDays(start, 7); label = "이번 주";
  } else if (/지난\s*달/.test(t)) {
    const month = shiftMonthString(currentMonthKst(), -1); start = new Date(Number(month.slice(0,4)), Number(month.slice(5,7))-1, 1); end = new Date(start.getFullYear(), start.getMonth()+1, 1); label = `${start.getMonth()+1}월`;
  } else {
    const dateMatch = t.match(/(?:(20\d{2})년\s*)?(\d{1,2})월\s*(\d{1,2})일/);
    if (dateMatch) {
      const y = Number(dateMatch[1] || now.getFullYear()), m = Number(dateMatch[2]), d = Number(dateMatch[3]);
      start = new Date(y, m - 1, d); end = addDays(start, 1); label = `${m}월 ${d}일`;
    } else {
      const monthMatch = t.match(/(?:(20\d{2})년\s*)?(\d{1,2})월(?:\s*요약)?$/);
      if (monthMatch) {
        const y = Number(monthMatch[1] || now.getFullYear()), m = Number(monthMatch[2]);
        start = new Date(y, m - 1, 1); end = new Date(y, m, 1); label = `${m}월`;
      } else {
        start = new Date(now.getFullYear(), now.getMonth(), 1); end = new Date(now.getFullYear(), now.getMonth()+1, 1); label = "이번 달";
      }
    }
  }
  return { start: formatDate(start), end: formatDate(end), label, month: formatDate(start).slice(0,7) };
}

async function maybeKakaoCta(env, userId = "", householdId = "", origin = "", kind = "analysis", href = "", label = "상세 분석 보기", cooldownHours = 24) {
  if (!origin || !userId || !householdId || !href) return "";
  const key = `kakao_cta_v215:${userId}:${householdId}:${kind}`;
  try {
    const raw = await getSettingValue(env, key);
    const last = Number(raw || 0);
    const cooldownMs = Math.max(0, Number(cooldownHours || 0)) * 60 * 60 * 1000;
    if (cooldownMs && last && Date.now() - last < cooldownMs) return "";
    await supabase(env, "/rest/v1/accountbook_settings?on_conflict=key", {
      method: "POST", headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify({ key, value: String(Date.now()) }),
    });
    return `\n\n${String(label || "자세히 보기").trim()}\n${href}`;
  } catch (err) {
    return "";
  }
}

function kakaoInviteManagementText(household = {}, origin = "") {
  const code = String(household?.invite_code || "-").trim() || "-";
  const householdId = String(household?.id || "").trim();
  const href = origin ? `${origin}/my/households${householdId ? `?household_id=${encodeURIComponent(householdId)}` : ""}` : "";
  return [
    "👥 구성원 초대하기",
    `초대코드: ${code}`,
    "",
    "구성원에게 아래 문장을 보내세요.",
    `가계부 참여 ${code}`,
    "",
    href ? "참여자·초대 관리" : "",
    href,
  ].filter(Boolean).join("\\n");
}

async function kakaoDateSummaryText(env, household = {}, user = {}, range = null, origin = "") {
  const rows = await fetchAdminRowsRange(env, { householdId: household.id, start: range.start, end: range.end, type: "all", limit: 6000 });
  const members = await fetchHouseholdMembers(env, household.id);
  const names = memberNameMap(members);
  const income = rows.filter((r) => r.type === "income").reduce((a, r) => a + Number(r.amount || 0), 0);
  const expenses = rows.filter((r) => r.type !== "income");
  const expense = expenses.reduce((a, r) => a + Number(r.amount || 0), 0);
  const byCategory = {};
  const byUser = {};
  for (const row of expenses) {
    const c = row.category || "기타"; byCategory[c] = (byCategory[c] || 0) + Number(row.amount || 0);
    const name = names[row.user_id] || "미지정"; byUser[name] = (byUser[name] || 0) + Number(row.amount || 0);
  }
  const categories = Object.entries(byCategory).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([k,v])=>`• ${k}: ${numberWithCommas(v)}원`);
  const users = Object.entries(byUser).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([k,v])=>`• ${k}: ${numberWithCommas(v)}원`);
  const cta = await maybeKakaoCta(env, user.id, household.id, origin, "analysis", `${origin}/my/analysis?household_id=${encodeURIComponent(household.id)}&month=${encodeURIComponent(range.month)}`);
  return [
    `📊 ${range.label} 요약`,
    "",
    `지출: ${numberWithCommas(expense)}원 · ${expenses.length}건`,
    `수입: ${numberWithCommas(income)}원`,
    "",
    categories.length ? "카테고리" : "", ...categories,
    users.length ? "" : "", users.length ? "결제자" : "", ...users,
  ].filter(Boolean).join("\n") + cta;
}

async function handlePreHouseholdGuidedFlow(env, { utterance, user, payload, nickname, origin }) {
  let state = await getKakaoFlowState(env, user.id, payload);
  if (!state || !["create_household", "join_household"].includes(state.flow)) return null;
  if (isKakaoFlowCancelCommand(utterance)) {
    await clearKakaoFlowState(env, user.id, payload);
    return { text: "진행 중인 설정을 취소했어요.", quickReplies: kakaoStartQuickReplies(false) };
  }
  if (state.flow === "create_household") {
    if (state.step === "kind") {
      const kind = parseKakaoCreateKind(utterance);
      if (!kind) return { text: "어떤 가계부인지 선택해 주세요.", quickReplies: kakaoCreateKindQuickReplies() };
      await saveKakaoFlowState(env, user.id, payload, { flow: "create_household", step: "name", data: { kind } });
      const suggestion = suggestedHouseholdName(kind, nickname);
      return {
        text: [`좋아요! ${kind} 가계부를 만들게요.`, "", "가계부 이름을 정해 주세요.", `예: ${suggestion}`].join("\n"),
        quickReplies: dedupeQuickReplies([[suggestion.slice(0,14), suggestion], ["취소", "취소"]]),
      };
    }
    if (state.step === "name") {
      const name = sanitizeHouseholdNameInput(utterance);
      if (!name) return { text: "가계부 이름을 2~40자로 입력해 주세요.\n예: 우리집 생활비", quickReplies: [["취소", "취소"]] };
      const household = await createUserHousehold(env, user.id, name, nickname);
      await clearKakaoFlowState(env, user.id, payload);
      const cta = await maybeKakaoCta(env, user.id, household.id, origin, "household", `${origin}/my/households`);
      return {
        text: [
          `✅ ‘${household.name}’ 가계부를 만들었어요.`,
          "",
          `초대코드: ${household.invite_code}`,
          "구성원에게 초대코드를 보내면 같은 가계부에 참여할 수 있어요.",
          "단톡방에서는 봇을 추가한 뒤 관리자 한 명이 초대코드로 한 번만 연결해 주세요.",
        ].join("\n") + cta,
        quickReplies: dedupeQuickReplies([["예산 설정", "예산 설정"], ["단톡방 연결", "단톡방 연결"], ["첫 기록", "입력 예시"]]),
      };
    }
  }
  if (state.flow === "join_household") {
    const code = parseBareInviteCode(utterance) || parseJoinCode(utterance);
    if (!code) return { text: "초대코드를 입력해 주세요.\n예: ABC123", quickReplies: [["취소", "취소"]] };
    const joined = await joinHouseholdByCode(env, user.id, code);
    if (!joined) return { text: `초대코드 ${code}를 찾지 못했어요. 다시 확인해 주세요.`, quickReplies: [["다시 입력", "초대코드로 참여"], ["취소", "취소"]] };
    await clearKakaoFlowState(env, user.id, payload);
    if (["pending","blocked","viewer"].includes(joined.join_role)) return { text: roleBlockedMessage(joined.join_role, joined.name) || `🕒 ‘${joined.name}’ 참여 요청을 보냈어요.`, quickReplies: [["도움말", "도움말"]] };
    return { text: `✅ ‘${joined.name}’ 가계부에 참여했어요.\n\n이제 ‘점심 12000원 국민카드’처럼 바로 기록할 수 있어요.`, quickReplies: kakaoStartQuickReplies(true) };
  }
  return null;
}

async function handleHouseholdGuidedFlow(env, { utterance, user, payload, household, nickname, origin }) {
  let state = await getKakaoFlowState(env, user.id, payload);
  if (!state || !["budget_setup", "member_alias"].includes(state.flow)) return null;
  if (isKakaoFlowCancelCommand(utterance)) {
    await clearKakaoFlowState(env, user.id, payload);
    return { text: "진행 중인 설정을 취소했어요.", quickReplies: kakaoStartQuickReplies(true) };
  }
  if (state.data?.household_id && state.data.household_id !== household.id) {
    const savedHousehold = await getHouseholdById(env, state.data.household_id);
    if (savedHousehold) household = savedHousehold;
  }
  if (state.flow === "member_alias") {
    const alias = normalizeText(utterance).replace(/^(내 이름|이름)\s*/, "").trim().slice(0, 30);
    if (!alias || alias.length < 2 || isKakaoGuidedCommand(alias)) return { text: "가계부에서 표시할 이름을 입력해 주세요.\n예: 인남, 엄마, 아빠", quickReplies: nickname ? [[nickname.slice(0,14), nickname], ["취소", "취소"]] : [["취소", "취소"]] };
    await saveMemberAlias(env, household.id, user.id, alias);
    await clearKakaoFlowState(env, user.id, payload);
    return { text: `✅ 이 가계부에서 내 이름을 ‘${alias}’로 설정했어요.\n\n앞으로 내가 기록한 지출은 ${alias} 지출로 집계됩니다.`, quickReplies: [["첫 기록", "입력 예시"], ["오늘 요약", "오늘 요약"]] };
  }
  if (state.flow === "budget_setup") {
    const role = await getHouseholdMemberRole(env, user.id, household.id);
    if (!["owner","admin"].includes(role)) {
      await clearKakaoFlowState(env, user.id, payload);
      return { text: "예산은 가계부 소유자 또는 관리자만 설정할 수 있어요.", quickReplies: [["예산 현황", "남은예산"], ["도움말", "도움말"]] };
    }
    const month = validMonth(state.data?.month) || currentMonthKst();
    if (state.step === "root") {
      const t = normalizeText(utterance);
      if (t === "전체 월 예산") {
        await saveKakaoFlowState(env, user.id, payload, { flow: "budget_setup", step: "amount", data: { household_id: household.id, month, category: "__total" } });
        return { text: "전체 월 예산을 얼마로 설정할까요?", quickReplies: kakaoBudgetAmountQuickReplies() };
      }
      if (t === "카테고리별 예산") {
        await saveKakaoFlowState(env, user.id, payload, { flow: "budget_setup", step: "category", data: { household_id: household.id, month } });
        return { text: "예산을 설정할 카테고리를 선택해 주세요.", quickReplies: kakaoBudgetCategoryQuickReplies() };
      }
      if (t === "지난달 예산 복사") {
        const copied = await copyKakaoBudgetsFromPreviousMonth(env, household.id, month);
        await clearKakaoFlowState(env, user.id, payload);
        return { text: copied.count ? `✅ ${copied.previous} 예산 ${copied.count}개를 ${month}로 복사했어요.` : `${copied.previous}에 복사할 예산이 없어요.`, quickReplies: [["예산 현황", "남은예산"], ["다른 예산", "예산 설정"]] };
      }
      return { text: "어떤 예산을 설정할까요?", quickReplies: kakaoBudgetRootQuickReplies() };
    }
    if (state.step === "category") {
      let rawCategory = normalizeText(utterance).replace(/^예산 카테고리\s*/, "");
      if (rawCategory === "직접 입력") {
        await saveKakaoFlowState(env, user.id, payload, { flow: "budget_setup", step: "category_custom", data: { household_id: household.id, month } });
        return { text: "예산을 설정할 카테고리 이름을 입력해 주세요.\n예: 육아/자녀", quickReplies: [["취소", "취소"]] };
      }
      const category = await resolveBudgetCategoryName(env, household.id, rawCategory);
      if (!category) return { text: "등록된 카테고리를 찾지 못했어요. 다시 선택하거나 직접 입력해 주세요.", quickReplies: kakaoBudgetCategoryQuickReplies() };
      await saveKakaoFlowState(env, user.id, payload, { flow: "budget_setup", step: "amount", data: { household_id: household.id, month, category } });
      return { text: `${category} 예산을 얼마로 설정할까요?`, quickReplies: kakaoBudgetAmountQuickReplies() };
    }
    if (state.step === "category_custom") {
      const category = await resolveBudgetCategoryName(env, household.id, utterance);
      if (!category) return { text: "웹에 등록된 기본·사용자 카테고리 이름으로 입력해 주세요.\n예: 식비, 육아/자녀", quickReplies: [["카테고리 선택", "예산 설정"], ["취소", "취소"]] };
      await saveKakaoFlowState(env, user.id, payload, { flow: "budget_setup", step: "amount", data: { household_id: household.id, month, category } });
      return { text: `${category} 예산을 얼마로 설정할까요?`, quickReplies: kakaoBudgetAmountQuickReplies() };
    }
    if (state.step === "amount") {
      if (normalizeText(utterance) === "직접 입력") return { text: "금액을 직접 입력해 주세요.\n예: 80만원", quickReplies: [["취소", "취소"]] };
      const amount = parseAmountValue(utterance);
      if (!amount) return { text: "금액을 확인하지 못했어요.\n예: 50만원, 1000000원", quickReplies: kakaoBudgetAmountQuickReplies() };
      const category = state.data?.category || "__total";
      await saveKakaoFlowState(env, user.id, payload, { flow: "budget_setup", step: "confirm", data: { household_id: household.id, month, category, amount } });
      return { text: `${month} ${category === "__total" ? "전체 월" : category} 예산을\n${numberWithCommas(amount)}원으로 설정할까요?`, quickReplies: [["설정하기", "설정하기"], ["다시 입력", "다시 입력"], ["취소", "취소"]] };
    }
    if (state.step === "confirm") {
      const t = normalizeText(utterance);
      if (t === "다시 입력") {
        await saveKakaoFlowState(env, user.id, payload, { flow: "budget_setup", step: "amount", data: state.data });
        return { text: "금액을 다시 입력해 주세요.", quickReplies: kakaoBudgetAmountQuickReplies() };
      }
      if (t !== "설정하기") return { text: "설정하려면 ‘설정하기’를 눌러 주세요.", quickReplies: [["설정하기", "설정하기"], ["다시 입력", "다시 입력"], ["취소", "취소"]] };
      const category = state.data?.category || "__total";
      const amount = Number(state.data?.amount || 0);
      await saveKakaoBudget(env, household.id, month, category, amount);
      await clearKakaoFlowState(env, user.id, payload);
      const cta = await maybeKakaoCta(env, user.id, household.id, origin, "budget", `${origin}/my/settings?household_id=${encodeURIComponent(household.id)}&month=${encodeURIComponent(month)}`);
      return {
        text: [`✅ ${category === "__total" ? "전체 월" : category} 예산을 설정했어요.`, "", `설정 금액: ${numberWithCommas(amount)}원`].join("\n") + cta,
        quickReplies: [["다른 카테고리", "예산 설정"], ["예산 현황", "남은예산"], ["첫 기록", "입력 예시"]],
      };
    }
  }
  return null;
}

async function handleKakaoSkillStable(request, env) {
  const origin = publicBaseUrl(env, new URL(request.url));
  let bodyText = "";
  let payload = null;
  let userKey = "unknown";
  let utterance = "";
  try {
    bodyText = await request.text();
    payload = JSON.parse(bodyText || "{}");
    userKey = getKakaoUserKey(payload);
    utterance = String(payload?.userRequest?.utterance || payload?.utterance || "").trim();
  } catch (err) {
    const rawUtterance = String(bodyText || "").trim();
    if (rawUtterance) {
      payload = {
        intent: { id: "raw-test", name: "raw-text-test" },
        userRequest: {
          timezone: "Asia/Seoul",
          params: {},
          block: { id: "raw-test-block", name: "raw-text-test" },
          utterance: rawUtterance,
          lang: "ko",
          user: { id: "raw-test-bot-user-key", type: "botUserKey", properties: { botUserKey: "raw-test-bot-user-key" } },
        },
        bot: { id: "raw-test-bot", name: "똑똑한가계부" },
        action: { id: "raw-test-action", name: "똑똑한가계부_스킬_v21", params: {}, detailParams: {}, clientExtra: {} },
        contexts: [],
      };
      userKey = getKakaoUserKey(payload);
      utterance = rawUtterance;
      rememberSkillEvent({ kind: "raw_text_test", user_key: userKey, utterance, detail: "invalid JSON accepted as test utterance" });
    } else {
      rememberSkillEvent({ kind: "bad_json", user_key: "unknown", utterance: "", detail: safeError(err) });
      return kakaoText(kakaoSkillSafeFallbackText(origin));
    }
  }

  const skillStartedAt = Date.now();
  rememberSkillEvent({ kind: "received", user_key: userKey, utterance, detail: "request accepted" });

  const rate = checkSkillRateLimit(userKey, env);
  if (!rate.ok) {
    rememberSkillEvent({ kind: "rate_limited", user_key: userKey, utterance, detail: `${rate.count}/${rate.limit}` });
    return rateLimitedKakaoText(origin);
  }

  const repeat = checkKakaoRepeatGuard(userKey, utterance, env);
  if (!repeat.ok) {
    rememberSkillEvent({ kind: "repeat_guard", user_key: userKey, utterance, detail: `${repeat.elapsedMs}ms` });
    rememberDuplicateEvent({ kind: "kakao_repeat", source: "kakao_skill", user_id: userKey, detail: utterance, path: "/skill", method: "POST" });
    return kakaoText(kakaoRepeatGuardText(origin));
  }

  try {
    const headers = new Headers(request.headers || {});
    headers.delete("content-length");
    headers.set("content-type", "application/json; charset=utf-8");
    const cloned = new Request(request.url, {
      method: "POST",
      headers,
      body: JSON.stringify(payload || {}),
    });
    const response = await handleKakaoSkill(cloned, env);
    const safeResponse = await normalizeKakaoSkillResponse(response, origin);
    const latencyMs = Date.now() - skillStartedAt;
    rememberSkillEvent({ kind: "ok", user_key: userKey, utterance, detail: `status=${response.status}; normalized=${safeResponse.status}; latency_ms=${latencyMs}` });
    const safeHeaders = new Headers(safeResponse.headers || {});
    safeHeaders.set("x-kakao-skill-latency-ms", String(latencyMs));
    return new Response(safeResponse.body, { status: safeResponse.status, statusText: safeResponse.statusText, headers: safeHeaders });
  } catch (err) {
    rememberSkillEvent({ kind: "error", user_key: userKey, utterance, detail: `${safeError(err)}; latency_ms=${Date.now() - skillStartedAt}` });
    return kakaoText(kakaoSkillSafeFallbackText(origin));
  }
}

async function handleKakaoSkill(request, env) {
  const handlerStartedAt = Date.now();
  const payload = await readJson(request);
  const origin = publicBaseUrl(env, new URL(request.url));
  const utterance = stripLeadingCommand(String(payload?.userRequest?.utterance || payload?.utterance || "").trim());
  const preParsedList = parseMultipleTransactions(utterance, payload);
  const strongTransactionInput = isStrongKakaoTransactionInput(utterance, preParsedList);
  const kakaoUserKey = getKakaoUserKey(payload);
  const nickname = getKakaoNickname(payload);

  if (!utterance) return kakaoText(kakaoStartText(false), kakaoStartQuickReplies(false));

  const bypassPublic = isKakaoStartCommand(utterance) || isHelpCommand(utterance) || isCommandMenuCommand(utterance) ||
    isKakaoCreateFlowCommand(utterance) || isKakaoJoinFlowCommand(utterance) || isKakaoBudgetSetupCommand(utterance) ||
    isKakaoMemberAliasCommand(utterance) || !!parseKakaoSummaryRange(utterance);
  const earlyReply = bypassPublic ? "" : kakaoPublicCommandReply(utterance, origin, env);
  if (earlyReply) return kakaoText(earlyReply);

  if (!env.SUPABASE_URL || !env.SUPABASE_SERVICE_ROLE_KEY) {
    if (isKakaoStartCommand(utterance) || isHelpCommand(utterance) || isCommandMenuCommand(utterance)) return kakaoText(kakaoStartText(false), kakaoStartQuickReplies(false));
    if (isBudgetCommand(utterance) || isKakaoBudgetSetupCommand(utterance)) return kakaoText(kakaoBudgetGuideText(origin));
    return kakaoText(kakaoSkillSafeFallbackText(origin));
  }

  const user = await ensureUser(env, kakaoUserKey, nickname);

  if (isKakaoStartCommand(utterance) || isCommandMenuCommand(utterance)) {
    await clearKakaoFlowState(env, user.id, payload);
    const households = await fetchUserHouseholds(env, user.id);
    const current = households[0] || null;
    return kakaoText(kakaoStartText(!!current, current?.name || ""), kakaoStartQuickReplies(!!current));
  }

  if (isHelpCommand(utterance)) {
    const households = await fetchUserHouseholds(env, user.id);
    return kakaoText(guidedHelpText(!!households.length), kakaoStartQuickReplies(!!households.length));
  }

  if (isKakaoCreateFlowCommand(utterance)) {
    await saveKakaoFlowState(env, user.id, payload, { flow: "create_household", step: "kind", data: {} });
    return kakaoText("어떤 가계부를 만들까요?", kakaoCreateKindQuickReplies());
  }

  if (isKakaoJoinFlowCommand(utterance)) {
    await saveKakaoFlowState(env, user.id, payload, { flow: "join_household", step: "code", data: {} });
    return kakaoText("초대코드를 입력해 주세요.\n예: ABC123", [["취소", "취소"]]);
  }

  const preFlow = await handlePreHouseholdGuidedFlow(env, { utterance, user, payload, nickname, origin });
  if (preFlow) return kakaoText(preFlow.text, preFlow.quickReplies || []);

  const createHouseholdName = parseCreateHouseholdCommand(utterance);
  if (createHouseholdName) {
    try {
      const createdHousehold = await createUserHousehold(env, user.id, createHouseholdName, nickname);
      const cta = await maybeKakaoCta(env, user.id, createdHousehold.id, origin, "household", `${origin}/my/households`);
      return kakaoText(`✅ ‘${createdHousehold.name}’ 가계부를 만들었어요.\n\n초대코드: ${createdHousehold.invite_code}\n구성원에게 이 코드를 보내면 함께 사용할 수 있어요.${cta}`, [["예산 설정", "예산 설정"], ["단톡방 연결", "단톡방 연결"], ["첫 기록", "입력 예시"]]);
    } catch (err) {
      return kakaoText("새 가계부 만들기가 잠시 지연되고 있어요.\n잠시 후 다시 시도해 주세요.");
    }
  }

  if (isHouseholdSwitchCommand(utterance)) return kakaoText(await kakaoHouseholdSwitchText(env, user, origin));

  const groupBindCode = parseGroupBindCommand(utterance);
  if (groupBindCode) {
    const result = await bindKakaoGroupByInviteCode(env, user, botGroupKey, groupBindCode);
    if (!result.ok) {
      if (result.error === "no_group_key") return kakaoText("👥 단톡방 연결은 그룹 채팅방 안에서만 사용할 수 있어요.\n\n단톡방에 봇을 추가한 뒤 아래처럼 보내주세요.\n단톡방 연결 ABC123");
      if (result.error === "not_found") return kakaoText(`초대코드 ${groupBindCode}를 찾지 못했어요. 코드를 다시 확인해 주세요.`);
      if (result.error === "not_allowed") return kakaoText(roleBlockedMessage(result.role, result.household?.name) || "이 가계부를 단톡방에 연결할 권한이 없습니다.");
      return kakaoText("단톡방 연결을 완료하지 못했어요. 잠시 후 다시 시도해 주세요.");
    }
    return kakaoText(`✅ 단톡방 연결 완료\n가계부: ${result.household.name}\n\n이제 이 방에서 구성원들이 함께 기록하고 조회할 수 있어요.`, [["첫 기록", "입력 예시"], ["예산 설정", "예산 설정"], ["오늘 요약", "오늘 요약"]]);
  }

  if (isGroupLinkInfoCommand(utterance)) {
    return kakaoText(await kakaoGroupInfoText(env, payload, origin, user), [["연결 방법", "단톡방 연결"], ["초대코드", "초대코드"]]);
  }

  const joinCode = parseJoinCode(utterance);
  if (joinCode) {
    try {
      const joined = await joinHouseholdByCode(env, user.id, joinCode);
      if (!joined) return kakaoText(`초대코드 ${joinCode}를 찾지 못했어요. 코드를 다시 확인해 주세요.`);
      if (["pending","blocked","viewer"].includes(joined.join_role)) return kakaoText(roleBlockedMessage(joined.join_role, joined.name) || `🕒 ‘${joined.name}’ 참여 요청을 보냈어요.`);
      return kakaoText(`✅ ‘${joined.name}’ 가계부에 참여했어요.\n\n이제 ‘점심 12000원 국민카드’처럼 바로 기록할 수 있어요.`, kakaoStartQuickReplies(true));
    } catch (err) {
      return kakaoText("초대코드 확인이 잠시 지연되고 있어요. 잠시 후 다시 시도해 주세요.");
    }
  }

  // V21.5.1: 회원목록과 그룹 연결을 병렬 조회하고 결과를 재사용해 중복 Supabase 왕복을 줄입니다.
  const botGroupKey = getKakaoBotGroupKey(payload);
  const [households, linkedGroupHousehold] = await Promise.all([
    fetchUserHouseholds(env, user.id),
    botGroupKey ? getLinkedKakaoGroupHousehold(env, botGroupKey) : Promise.resolve(null),
  ]);
  const pendingHousehold = households.find((h) => String(h.role || "") === "pending") || null;
  const activeHouseholds = households.filter((h) => !["pending", "blocked"].includes(String(h.role || "member")));
  if (pendingHousehold && !activeHouseholds.length && !isHelpCommand(utterance) && !isLinkCommand(utterance) && !isInviteCommand(utterance)) {
    return kakaoText(`🕒 아직 승인 대기 중입니다.\n가계부: ${pendingHousehold.name}\n\n관리자가 참여자를 승인해야 기록할 수 있어요.`);
  }
  if (!households.length) return kakaoText(kakaoStartText(false), kakaoStartQuickReplies(false));

  let household = null;
  let accessRole = "";
  if (linkedGroupHousehold?.id) {
    household = { ...linkedGroupHousehold, from_group_link: true, bot_group_key: botGroupKey };
    const membership = households.find((h) => String(h.id) === String(linkedGroupHousehold.id));
    accessRole = membership?.role || await ensurePendingMemberIfMissing(env, linkedGroupHousehold.id, user.id);
  }
  if (!household) {
    household = activeHouseholds[0] || households[0];
    accessRole = household?.role || "member";
  }

  const directAlias = parseDirectMemberAliasCommand(utterance);
  if (directAlias) {
    await saveMemberAlias(env, household.id, user.id, directAlias);
    await clearKakaoFlowState(env, user.id, payload);
    return kakaoText(`✅ 이 가계부에서 내 이름을 ‘${directAlias}’로 변경했어요.\n\n앞으로 내가 기록한 지출은 ${directAlias} 지출로 집계됩니다.`, [["오늘 요약", "오늘 요약"], ["첫 기록", "입력 예시"]]);
  }

  if (isKakaoMemberAliasCommand(utterance)) {
    await saveKakaoFlowState(env, user.id, payload, { flow: "member_alias", step: "name", data: { household_id: household.id } });
    return kakaoText("가계부에서 표시할 내 이름을 입력해 주세요.\n예: 인남, 엄마, 아빠\n\n한 번에 바꾸려면 ‘닉네임 인남으로 변경’처럼 입력할 수도 있어요.", nickname ? [[nickname.slice(0,14), nickname], ["취소", "취소"]] : [["취소", "취소"]]);
  }

  if (isKakaoBudgetSetupCommand(utterance)) {
    if (!["owner","admin"].includes(accessRole)) return kakaoText("예산은 가계부 소유자 또는 관리자만 설정할 수 있어요.", [["예산 현황", "남은예산"]]);
    await saveKakaoFlowState(env, user.id, payload, { flow: "budget_setup", step: "root", data: { household_id: household.id, month: currentMonthKst() } });
    return kakaoText("어떤 예산을 설정할까요?", kakaoBudgetRootQuickReplies());
  }

  if (!strongTransactionInput) {
    const guided = await handleHouseholdGuidedFlow(env, { utterance, user, payload, household, nickname, origin });
    if (guided) return kakaoText(guided.text, guided.quickReplies || []);
  }

  const directBudget = parseDirectBudgetSetCommand(utterance);
  if (directBudget) {
    if (!["owner","admin"].includes(accessRole)) return kakaoText("예산은 가계부 소유자 또는 관리자만 설정할 수 있어요.");
    const category = await resolveBudgetCategoryName(env, household.id, directBudget.category);
    if (!category) return kakaoText("등록된 카테고리를 찾지 못했어요.\n‘예산 설정’을 입력해 단계별로 선택해 주세요.", [["예산 설정", "예산 설정"]]);
    await saveKakaoBudget(env, household.id, directBudget.month, category, directBudget.amount);
    return kakaoText(`✅ ${directBudget.month} ${category === "__total" ? "전체 월" : category} 예산을 설정했어요.\n\n설정 금액: ${numberWithCommas(directBudget.amount)}원`, [["예산 현황", "남은예산"], ["다른 예산", "예산 설정"]]);
  }

  if (["blocked","viewer","pending"].includes(accessRole) && !isHelpCommand(utterance) && !isLinkCommand(utterance) && !isSummaryCommand(utterance) && !isRecentCommand(utterance)) {
    return kakaoText(roleBlockedMessage(accessRole, household.name));
  }

  if (!strongTransactionInput) {
    const kakaoEditReply = await handleKakaoDailyEditFlow(env, { utterance, household, user, origin });
    if (kakaoEditReply) return kakaoText(kakaoEditReply);
  }

  if (isLinkCommand(utterance)) return kakaoText(linkText(origin, household.invite_code));

  if (isInviteCommand(utterance)) {
    return kakaoText(kakaoInviteManagementText(household, origin), [["단톡방 연결", "단톡방 연결"], ["도움말", "도움말"]]);
  }

  if (isBudgetCommand(utterance)) return kakaoText(await kakaoBudgetStatusText(env, household.id, currentMonthKst(), origin));

  if (isSettlementCommand(utterance)) return kakaoText(await kakaoSettlementText(env, household));

  const summaryRange = parseKakaoSummaryRange(utterance);
  if (summaryRange) return kakaoText(await kakaoDateSummaryText(env, household, user, summaryRange, origin));

  if (isSummaryCommand(utterance)) {
    const summary = await getMonthSummary(env, household.id, currentMonthKst());
    const reserveLine = await kakaoReserveAlert(env, household.id);
    return kakaoText(`${formatSummary(summary, currentMonthKst())}${reserveLine}`);
  }

  if (isRecentCommand(utterance)) {
    const rows = await getRecentTransactions(env, household.id, user.id, 5);
    return kakaoText(formatRecentTransactions(rows));
  }

  if (isUndoCommand(utterance)) {
    const removed = await deleteLatestUserTransaction(env, household.id, user.id);
    if (!removed) return kakaoText("삭제할 최근 입력 내역이 없습니다.");
    const typeText = removed.type === "income" ? "수입" : "지출";
    return kakaoText(`↩️ 최근 입력 1건 삭제 완료\n${removed.transaction_date} ${typeText} ${numberWithCommas(removed.amount)}원 ${removed.memo || removed.category || ""}`);
  }

  const parsedList = preParsedList;
  if (!parsedList.length) return kakaoText(kakaoNoMatchGuideText(utterance, origin));

  const [customCategoryRows, paymentAssetRows] = await Promise.all([
    fetchCustomCategories(env, household.id),
    fetchPaymentAssets(env, household.id),
  ]);
  const finalParsedList = applyUserSettingsToParsedTransactions(parsedList, customCategoryRows, paymentAssetRows);

  const kakaoBulkLimit = Math.min(80, Math.max(1, Number(env.KAKAO_BULK_LIMIT || 25)));
  const limitedParsedList = finalParsedList.slice(0, kakaoBulkLimit);
  const rowsToInsert = limitedParsedList.map((parsed) => ({
    household_id: household.id, user_id: user.id, type: parsed.type, amount: parsed.amount,
    category: parsed.category, memo: parsed.memo, payment_method: parsed.payment_method,
    transaction_date: parsed.transaction_date, source: "kakao_skill", source_user_key: kakaoUserKey,
    raw_text: parsed.raw_text || utterance,
  }));

  let savedRows = [];
  try { savedRows = await insertKakaoTransactions(env, rowsToInsert); }
  catch (err) { return kakaoText(kakaoSaveDelayText(origin)); }
  if (!savedRows.length) return kakaoText(kakaoSaveDelayText(origin));

  if (limitedParsedList.length > 1) {
    // 대량 입력에서 번호 조회를 건별 순차 실행하면 카카오 제한 시간을 넘길 수 있어 저장 결과만 즉시 반환합니다.
    const lines = savedRows.slice(0, 6).map((row) => {
      const memo = row.memo || row.raw_text || row.category || "기록";
      return `${row.transaction_date} - ${memo} / ${numberWithCommas(row.amount)}원 / ${row.payment_method || "-"}`;
    });
    return kakaoText(`✅ ${savedRows.length}건 저장했어요.\n가계부: ${household.name}\n${lines.join("\n")}\n\n수정할 번호는 ‘오늘 기록’에서 확인해 주세요.`);
  }

  const parsed = limitedParsedList[0];
  const saved = savedRows[0] || parsed;
  const icon = parsed.type === "income" ? "💰" : "💸";
  const typeText = parsed.type === "income" ? "수입" : "지출";
  const enrichBudgetMs = Math.max(150, Math.min(700, 3900 - (Date.now() - handlerStartedAt)));
  const [seq, aliases] = await Promise.all([
    optionalWithin(dailySeqForKakaoRow(env, household.id, user.id, saved), enrichBudgetMs, 0),
    optionalWithin(fetchMemberAliasMap(env, household.id), enrichBudgetMs, {}),
  ]);
  const payerName = aliases?.[user.id] || nickname || "나";
  const numberedLine = seq ? kakaoRowLabel(saved, seq) : `${saved.memo || saved.raw_text || saved.category || "기록"} / ${numberWithCommas(saved.amount)}원 / ${saved.payment_method || "-"} / ${saved.category || typeText}`;
  const editGuide = seq ? `\n\n수정: ${twoDigitSeq(seq)}번 금액 13000원\n삭제: ${twoDigitSeq(seq)}번 삭제` : `\n\n수정할 번호는 ‘오늘 기록’에서 확인해 주세요.`;
  return kakaoText(`${icon} ${typeText} 저장했어요 😊\n${numberedLine}\n결제자: ${payerName}${editGuide}`);
}

const KAKAO_RETRY_DEDUP_SECONDS = 120;

async function dedupeKakaoRowsBeforeInsert(env, cleanRows = []) {
  const existing = [];
  const fresh = [];
  for (const row of cleanRows) {
    // Only collapse retries within a short window so genuine repeat entries
    // (e.g. two coffees the same day) are still saved. Manual §5: 재전송 멱등 처리.
    const dup = await findExactDuplicateTransaction(env, row, { withinSeconds: KAKAO_RETRY_DEDUP_SECONDS });
    if (dup) existing.push(dup);
    else fresh.push(row);
  }
  return { existing, fresh };
}

async function insertKakaoTransactions(env, rows) {
  if (!Array.isArray(rows) || !rows.length) return [];
  const bulkLimit = Math.min(80, Math.max(1, Number(env.KAKAO_BULK_LIMIT || 25)));
  const originalCount = rows.length;
  if (originalCount > bulkLimit) rememberDuplicateEvent({ kind: "bulk_limited", source: "kakao_skill", detail: `${originalCount} requested, ${bulkLimit} processed`, path: "/skill", method: "POST" });
  rows = rows.slice(0, bulkLimit);
  const cleanRows = rows.map((r) => ({
    household_id: r.household_id,
    user_id: r.user_id,
    type: r.type === "income" ? "income" : "expense",
    amount: Math.max(0, Math.round(Number(r.amount || 0))),
    category: String(r.category || "기타").slice(0, 80),
    memo: String(r.memo || "").slice(0, 160),
    payment_method: String(r.payment_method || "").slice(0, 40),
    transaction_date: /^20\d{2}-\d{2}-\d{2}$/.test(String(r.transaction_date || "")) ? String(r.transaction_date) : formatDate(nowKstDate()),
    source: "kakao_skill",
    source_user_key: String(r.source_user_key || "").slice(0, 160),
    raw_text: String(r.raw_text || "").slice(0, 300),
  })).filter((r) => r.household_id && r.user_id && r.amount > 0);

  if (!cleanRows.length) return [];

  const { existing, fresh } = await dedupeKakaoRowsBeforeInsert(env, cleanRows);
  for (const dup of existing) rememberDuplicateEvent({ kind: "duplicate_skipped", source: "kakao_skill", household_id: dup.household_id, user_id: dup.user_id, amount: dup.amount, transaction_date: dup.transaction_date, detail: dup.memo || dup.raw_text || "", path: "/skill", method: "POST" });
  let insertedRows = [];
  if (fresh.length) {
    const inserted = await supabase(env, "/rest/v1/transactions", {
      method: "POST",
      headers: { Prefer: "return=representation" },
      body: JSON.stringify(fresh),
    });
    insertedRows = Array.isArray(inserted) ? inserted : (inserted ? [inserted] : []);
  }

  return [...existing, ...insertedRows];
}


async function handleKakaoRecentDebug(request, env, url) {
  const limit = Math.min(50, Math.max(1, Number(url.searchParams.get("limit") || 20)));
  const params = new URLSearchParams();
  params.set("select", "id,household_id,user_id,type,amount,category,memo,payment_method,transaction_date,source,source_user_key,raw_text,created_at");
  params.set("source", "eq.kakao_skill");
  params.set("order", "created_at.desc");
  params.set("limit", String(limit));
  const rows = await supabase(env, `/rest/v1/transactions?${params.toString()}`, { method: "GET" }) || [];
  return htmlResponse(`<!doctype html><html lang="ko"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"/><title>Kakao Recent</title><style>body{font-family:system-ui,sans-serif;background:#f6f7f9;margin:0;padding:20px}table{width:100%;border-collapse:collapse;background:#fff}th,td{border:1px solid #ddd;padding:8px;font-size:13px}th{background:#f1f5f9}code{font-size:12px}</style></head><body><h2>최근 카카오 저장 내역</h2><p>최근 ${rows.length}건 · <a href="/ledger?all=1">기록 전체 보기</a></p><table><thead><tr><th>created</th><th>date</th><th>type</th><th>amount</th><th>category</th><th>memo</th><th>household</th><th>user key</th></tr></thead><tbody>${rows.map((r) => `<tr><td>${escapeHtml(r.created_at || "")}</td><td>${escapeHtml(r.transaction_date || "")}</td><td>${escapeHtml(r.type || "")}</td><td>${numberWithCommas(r.amount)}</td><td>${escapeHtml(r.category || "")}</td><td>${escapeHtml(r.memo || r.raw_text || "")}</td><td><code>${escapeHtml(r.household_id || "")}</code></td><td><code>${escapeHtml(r.source_user_key || "")}</code></td></tr>`).join("")}</tbody></table></body></html>`);
}


async function handleApi(request, env, url) {
  if (!isAdmin(request, env) && !(await verifyAdminSession(request, env))) {
    return jsonResponse({ ok: false, error: "unauthorized" }, 401);
  }

  const method = request.method;
  const path = url.pathname;

  if (path === "/api/bootstrap" && method === "GET") {
    const households = await supabase(env, "/rest/v1/households?select=id,name,invite_code,created_at&order=created_at.asc", { method: "GET" }) || [];
    const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
    const householdId = url.searchParams.get("household_id") || "";
    const defaultHouseholdId = households[0]?.id || "";
    const stats = await getStats(env, householdId, month);
    return jsonResponse({ ok: true, app: appName(env), month, selected_household_id: householdId, default_household_id: defaultHouseholdId, households, summary: { total_balance: stats.totals.balance, month_income: stats.totals.income, month_expense: stats.totals.expense }, stats });
  }

  if (path === "/api/transactions" && method === "GET") {
    return listTransactions(env, url);
  }

  if (path === "/api/transactions" && method === "POST") {
    const body = normalizeApiTransactionBody(await readJson(request));
    const created = await createManualTransaction(env, body);
    return jsonResponse({ ok: true, item: created });
  }

  if (path === "/api/transactions/batch" && method === "PATCH") {
    const body = await readJson(request);
    const ids = [...new Set((body.ids || []).map((x) => String(x || "").trim()).filter(Boolean))];
    if (!ids.length) return jsonResponse({ ok: false, error: "ids_required" }, 400);
    const patch = normalizeApiTransactionBody(body, true);
    if (!Object.keys(patch).length) return jsonResponse({ ok: false, error: "empty_patch" }, 400);
    for (const id of ids) await updateTransaction(env, id, patch);
    return jsonResponse({ ok: true, updatedCount: ids.length });
  }

  const txMatch = path.match(/^\/api\/transactions\/([0-9a-fA-F-]{32,36})$/);
  if (txMatch && method === "PATCH") {
    const body = normalizeApiTransactionBody(await readJson(request), true);
    const updated = await updateTransaction(env, txMatch[1], body);
    return jsonResponse({ ok: true, item: updated });
  }

  if (txMatch && method === "DELETE") {
    await supabase(env, `/rest/v1/transactions?id=eq.${encodeURIComponent(txMatch[1])}`, {
      method: "DELETE",
      headers: { Prefer: "return=minimal" },
    });
    return jsonResponse({ ok: true });
  }

  if (path === "/api/stats" && method === "GET") {
    const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
    const householdId = url.searchParams.get("household_id") || "";
    const stats = await getStats(env, householdId, month);
    return jsonResponse({ ok: true, month, ...stats });
  }

  if (path === "/api/calendar" && method === "GET") {
    const month = validMonth(url.searchParams.get("month")) || currentMonthKst();
    const householdId = url.searchParams.get("household_id") || "";
    const calendar = await getCalendar(env, householdId, month);
    return jsonResponse({ ok: true, month, days: calendar });
  }

  return jsonResponse({ ok: false, error: "api_not_found" }, 404);
}


function normalizeApiTransactionBody(body = {}, partial = false) {
  const out = {};
  const map = {
    household_id: body.household_id,
    user_id: body.user_id,
    type: body.type,
    amount: body.amount,
    category: body.category,
    memo: body.memo ?? body.description,
    payment_method: body.payment_method ?? body.method,
    transaction_date: body.transaction_date ?? body.date,
    source: body.source || "ledger_live",
  };
  for (const [k, v] of Object.entries(map)) {
    if (partial && (v === undefined || v === null || v === "")) continue;
    out[k] = v;
  }
  return out;
}

function isAdmin(request, env) {
  const expected = env.ADMIN_PASSWORD || "";
  if (!expected) return false;
  const auth = request.headers.get("authorization") || "";
  return auth === `Bearer ${expected}`;
}

async function readJson(request) {
  const text = await request.text();
  if (!text) return {};
  try {
    return JSON.parse(text);
  } catch (_) {
    return {};
  }
}


function getKakaoBotGroupKey(payload) {
  const props = payload?.userRequest?.user?.properties || {};
  const userReq = payload?.userRequest || {};
  const chat = userReq?.chat || payload?.chat || payload?.group || {};
  const candidates = [
    props.botGroupKey,
    props.groupKey,
    userReq.botGroupKey,
    userReq.groupKey,
    chat.botGroupKey,
    chat.groupKey,
    chat.id,
    payload?.botGroupKey,
    payload?.groupKey,
  ].map((x) => String(x || "").trim()).filter(Boolean);
  const stable = candidates.find((x) => x && x !== "unknown-group");
  return stable ? stable.slice(0, 160) : "";
}

function kakaoGroupLinksSettingsKey() {
  return "kakao_group_links";
}

async function fetchKakaoGroupLinkMap(env) {
  try {
    const value = await getSettingValue(env, kakaoGroupLinksSettingsKey());
    if (!value) return {};
    const parsed = typeof value === "string" ? JSON.parse(value || "{}") : value;
    const out = {};
    for (const [k, v] of Object.entries(safeObject(parsed))) {
      const groupKey = String(k || "").trim();
      const item = safeObject(v);
      if (groupKey && item.household_id) {
        out[groupKey] = {
          household_id: String(item.household_id || ""),
          household_name: String(item.household_name || ""),
          invite_code: String(item.invite_code || ""),
          linked_by: String(item.linked_by || ""),
          linked_at: String(item.linked_at || ""),
        };
      }
    }
    return out;
  } catch (err) {
    return {};
  }
}

async function saveKakaoGroupLink(env, groupKey = "", household = {}, userId = "") {
  const key = String(groupKey || "").trim();
  if (!key || !household?.id) return {};
  const map = await fetchKakaoGroupLinkMap(env);
  map[key] = {
    household_id: household.id,
    household_name: household.name || "",
    invite_code: household.invite_code || "",
    linked_by: userId || "",
    linked_at: new Date().toISOString(),
  };
  await supabase(env, "/rest/v1/accountbook_settings?on_conflict=key", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify({ key: kakaoGroupLinksSettingsKey(), value: JSON.stringify(map) }),
  });
  return map[key];
}

async function getLinkedKakaoGroupHousehold(env, groupKey = "") {
  const key = String(groupKey || "").trim();
  if (!key) return null;
  const map = await fetchKakaoGroupLinkMap(env);
  const linked = map[key];
  if (!linked?.household_id) return null;
  const rows = await optionalSupabase(env, `/rest/v1/households?id=eq.${encodeURIComponent(linked.household_id)}&select=id,name,invite_code,created_at&limit=1`, { method: "GET" }, []) || [];
  return rows?.[0] || null;
}

async function ensurePendingMemberIfMissing(env, householdId = "", userId = "") {
  if (!householdId || !userId) return "";
  const role = await getHouseholdMemberRole(env, userId, householdId);
  if (role) return role;
  await optionalSupabase(env, "/rest/v1/household_members?on_conflict=household_id,user_id", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify({ household_id: householdId, user_id: userId, role: "pending" }),
  }, null);
  return "pending";
}

async function resolveKakaoHousehold(env, user = {}, nickname = "", payload = {}) {
  const groupKey = getKakaoBotGroupKey(payload);
  if (groupKey) {
    const linked = await getLinkedKakaoGroupHousehold(env, groupKey);
    if (linked?.id) {
      await ensurePendingMemberIfMissing(env, linked.id, user.id);
      return { ...linked, from_group_link: true, bot_group_key: groupKey };
    }
  }
  return await ensurePrimaryHousehold(env, user.id, nickname);
}

async function bindKakaoGroupByInviteCode(env, user = {}, groupKey = "", code = "") {
  const normalized = String(code || "").trim().toUpperCase();
  if (!groupKey) return { ok: false, error: "no_group_key" };
  if (!normalized) return { ok: false, error: "no_code" };
  const householdRows = await supabase(env, `/rest/v1/households?invite_code=eq.${encodeURIComponent(normalized)}&select=id,name,invite_code,created_at&limit=1`, { method: "GET" });
  const household = householdRows?.[0];
  if (!household) return { ok: false, error: "not_found", code: normalized };
  let role = await getHouseholdMemberRole(env, user.id, household.id);
  if (!role) {
    // 웹 접속은 이름+개인코드, 카카오 챗봇은 botUserKey를 사용하므로
    // 같은 사람이더라도 사용자키가 다를 수 있습니다. 단톡방 연결은 초대코드가
    // 맞는 경우를 연결 승인 증거로 보고, 해당 카카오 사용자를 구성원으로 연결합니다.
    await supabase(env, "/rest/v1/household_members?on_conflict=household_id,user_id", {
      method: "POST",
      headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify({ household_id: household.id, user_id: user.id, role: "member" }),
    });
    role = "member";
  }
  if (["blocked"].includes(role)) return { ok: false, error: "not_allowed", role, household };
  const linked = await saveKakaoGroupLink(env, groupKey, household, user.id);
  return { ok: true, role, household, linked };
}

